// === MICRO ARCADE bundle (auto-generated by build.js — do not edit) ===
(function(){
"use strict";
var __games = [];

// ---- js/core/palette.js ----
// レトロカラーパレット（CRT/ゲームボーイ風）。色数を絞って雰囲気を統一する。
const PALETTES = {
  GREEN: {
    name: 'GREEN CRT',
    bg:   '#0b1a0b', // 背景（暗緑）
    dark: '#10300f', // 影
    dim:  '#1f5d1d', // 弱
    mid:  '#39ff14', // 主役の蛍光グリーン
    fg:   '#9dff7a', // 明
    hi:   '#e8ffe0', // ハイライト
    warn: '#ffd23f', // 警告/アクセント
    bad:  '#ff5b5b', // 敵/失敗
  },
  AMBER: {
    name: 'AMBER',
    bg:   '#1a0f00',
    dark: '#2b1900',
    dim:  '#7a4a00',
    mid:  '#ffb000',
    fg:   '#ffcf63',
    hi:   '#fff0c8',
    warn: '#7af0ff',
    bad:  '#ff5b5b',
  },
};

// 現在のテーマ（メニューから切替可能）
const theme = { current: PALETTES.GREEN };

function P() { return theme.current; }


// ---- js/core/audio.js ----
// 矩形波の短いBEEP音。80年代マイコン風のSE。
// WebAudioはユーザー操作後でないと鳴らせないため、最初の入力でresume()する。
class Audio {
  constructor() {
    this.ctx = null;
    this.enabled = true;
  }

  // 初回のユーザー操作で呼ぶ
  unlock() {
    if (!this.ctx) {
      const AC = window.AudioContext || window.webkitAudioContext;
      if (AC) this.ctx = new AC();
    }
    if (this.ctx && this.ctx.state === 'suspended') this.ctx.resume();
  }

  // freq: 周波数(Hz), dur: 長さ(秒), type: 'square'|'sine'|'triangle'|'sawtooth'
  beep(freq = 440, dur = 0.08, type = 'square', vol = 0.15) {
    if (!this.enabled || !this.ctx) return;
    const t0 = this.ctx.currentTime;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, t0);
    gain.gain.setValueAtTime(vol, t0);
    gain.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    osc.connect(gain).connect(this.ctx.destination);
    osc.start(t0);
    osc.stop(t0 + dur);
  }

  // 連続した音階（メロディ/効果音シーケンス）
  sequence(notes) {
    if (!this.enabled || !this.ctx) return;
    let t = 0;
    for (const n of notes) {
      setTimeout(() => this.beep(n.freq, n.dur || 0.08, n.type || 'square', n.vol || 0.15), t * 1000);
      t += (n.gap != null ? n.gap : (n.dur || 0.08));
    }
  }

  // よく使うSE
  move()    { this.beep(220, 0.04, 'square', 0.08); }
  pick()    { this.beep(880, 0.07, 'square', 0.14); }
  good()    { this.sequence([{ freq: 660 }, { freq: 880 }, { freq: 1320 }]); }
  bad()     { this.beep(120, 0.25, 'sawtooth', 0.18); }
  select()  { this.beep(520, 0.05, 'square', 0.12); }
}


// ---- js/core/storage.js ----
// ハイスコア等のローカル保存。localStorageの薄いラッパ。
const PREFIX = 'microarcade.';

const Storage = {
  getHigh(gameId) {
    const v = localStorage.getItem(PREFIX + 'high.' + gameId);
    return v ? parseInt(v, 10) : 0;
  },
  // 新記録なら保存してtrueを返す
  setHigh(gameId, score) {
    const cur = this.getHigh(gameId);
    if (score > cur) {
      localStorage.setItem(PREFIX + 'high.' + gameId, String(score));
      return true;
    }
    return false;
  },
  get(key, def = null) {
    const v = localStorage.getItem(PREFIX + key);
    return v == null ? def : v;
  },
  set(key, val) {
    localStorage.setItem(PREFIX + key, String(val));
  },
};


// ---- js/core/engine.js ----
// MICRO ARCADE エンジン。論理解像度を固定し、スクロールなしで画面にフィットさせる。
// 各ゲームは Scene を継承して enter/update/render/onInput を実装する。

// 論理解像度（全ゲーム共通の座標系）。実際の表示はこれを拡大縮小する。
const W = 360;
const H = 640;

// シーン基底クラス。これが「ゲーム実装の契約」。
class Scene {
  constructor(engine) {
    this.engine = engine;
  }
  enter() {}                 // シーン開始時の初期化
  exit() {}                  // シーン終了時の後始末
  update(dt) {}              // 毎フレームのロジック（dt: 秒）
  render(ctx) {}             // 毎フレームの描画
  // action: 'up'|'down'|'left'|'right'|'tap'|'confirm'|'back'
  // data: tapの場合 {x,y}（論理座標）
  onInput(action, data) {}
}

class Engine {
  constructor(canvas) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d');
    this.audio = new Audio();
    this.storage = Storage;
    this.scene = null;
    this.last = 0;
    this.scale = 1;
    this.offsetX = 0;
    this.offsetY = 0;
    // 全ゲーム共通の「メニューへ戻る」ボタン（左上）。各ゲームは左上HUDを x>=52 から描く。
    this.backBtn = { x: 6, y: 8, w: 42, h: 36 };
    // 押しっぱなし状態（LANDER等の連続操作用）。論理座標。update内で毎フレーム参照できる。
    this.pointer = { down: false, x: 0, y: 0 };
    this._resize = this._resize.bind(this);
    this._loop = this._loop.bind(this);
    this._setupInput();
    window.addEventListener('resize', this._resize);
    this._resize();
  }

  // 画面サイズに合わせてキャンバスを拡大（アスペクト比維持・スクロールなし）
  _resize() {
    const dpr = window.devicePixelRatio || 1;
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    this.scale = Math.min(vw / W, vh / H);
    const cssW = Math.floor(W * this.scale);
    const cssH = Math.floor(H * this.scale);
    this.canvas.style.width = cssW + 'px';
    this.canvas.style.height = cssH + 'px';
    this.canvas.width = Math.floor(W * this.scale * dpr);
    this.canvas.height = Math.floor(H * this.scale * dpr);
    this.ctx.setTransform(this.scale * dpr, 0, 0, this.scale * dpr, 0, 0);
    this.ctx.imageSmoothingEnabled = false; // ドット絵をクッキリ
    this.offsetX = (vw - cssW) / 2;
    this.offsetY = (vh - cssH) / 2;
  }

  changeScene(scene) {
    if (this.scene && this.scene.exit) this.scene.exit();
    this.scene = scene;
    if (scene.enter) scene.enter();
  }

  start(scene) {
    this.changeScene(scene);
    this.last = performance.now();
    requestAnimationFrame(this._loop);
  }

  _loop(now) {
    let dt = (now - this.last) / 1000;
    if (dt > 0.1) dt = 0.1; // タブ復帰時の暴走防止
    this.last = now;
    const ctx = this.ctx;
    // 背景クリア
    ctx.fillStyle = P().bg;
    ctx.fillRect(0, 0, W, H);
    if (this.scene) {
      // 1ゲームの例外でループ全体（＝アプリ）が停止しないよう保護する
      try {
        this.scene.update(dt);
        this.scene.render(ctx);
        if (!this.scene.isRoot) this._drawBack(); // メニュー以外はBACKボタンを上に重ねる
      } catch (e) {
        console.error('[scene error]', e);
      }
    }
    requestAnimationFrame(this._loop); // 例外があっても次フレームは必ず予約する
  }

  // ---- 入力 ----
  _setupInput() {
    const dispatch = (action, data) => {
      this.audio.unlock();
      // BACKボタンのタップはゲームに渡さず、メニューへ戻す（メニュー画面では無効）
      if (action === 'tap' && data && this.scene && !this.scene.isRoot && this._inBack(data)) {
        this.audio.select();
        if (this.toMenu) this.toMenu();
        return;
      }
      if (this.scene && this.scene.onInput) this.scene.onInput(action, data);
    };

    // キーボード
    window.addEventListener('keydown', (e) => {
      const k = e.key;
      if (k === 'ArrowUp' || k === 'w') { dispatch('up'); e.preventDefault(); }
      else if (k === 'ArrowDown' || k === 's') { dispatch('down'); e.preventDefault(); }
      else if (k === 'ArrowLeft' || k === 'a') { dispatch('left'); e.preventDefault(); }
      else if (k === 'ArrowRight' || k === 'd') { dispatch('right'); e.preventDefault(); }
      else if (k === 'Enter' || k === ' ') { dispatch('confirm'); e.preventDefault(); }
      else if (k === 'Escape' || k === 'Backspace') { dispatch('back'); e.preventDefault(); }
    });

    // タッチ／マウス（スワイプ判定＋タップ）
    const SWIPE = 24; // スワイプとみなす最小移動量(px CSS)
    let sx = 0, sy = 0, st = 0, moved = false;
    const toLogical = (clientX, clientY) => {
      const r = this.canvas.getBoundingClientRect();
      return {
        x: (clientX - r.left) / this.scale,
        y: (clientY - r.top) / this.scale,
      };
    };
    const setPointer = (clientX, clientY, isDown) => {
      const lp = toLogical(clientX, clientY);
      this.pointer.x = lp.x; this.pointer.y = lp.y;
      if (isDown != null) this.pointer.down = isDown;
    };
    const onStart = (x, y) => { sx = x; sy = y; st = performance.now(); moved = false; setPointer(x, y, true); };
    const onMove = (x, y) => { setPointer(x, y, null); };
    const onEnd = (x, y) => {
      setPointer(x, y, false);
      const dx = x - sx, dy = y - sy;
      const adx = Math.abs(dx), ady = Math.abs(dy);
      if (adx < SWIPE && ady < SWIPE) {
        dispatch('tap', toLogical(x, y)); // タップ
      } else if (adx > ady) {
        dispatch(dx > 0 ? 'right' : 'left');
      } else {
        dispatch(dy > 0 ? 'down' : 'up');
      }
    };

    const c = this.canvas;
    c.addEventListener('touchstart', (e) => {
      const t = e.changedTouches[0]; onStart(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });
    c.addEventListener('touchmove', (e) => {
      const t = e.changedTouches[0]; onMove(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });
    c.addEventListener('touchend', (e) => {
      const t = e.changedTouches[0]; onEnd(t.clientX, t.clientY);
      e.preventDefault();
    }, { passive: false });

    // マウス（PC確認用）
    let down = false;
    c.addEventListener('mousedown', (e) => { down = true; onStart(e.clientX, e.clientY); });
    c.addEventListener('mousemove', (e) => { if (down) onMove(e.clientX, e.clientY); });
    c.addEventListener('mouseup', (e) => { if (down) onEnd(e.clientX, e.clientY); down = false; });
  }

  // タップ座標がBACKボタン内か
  _inBack(data) {
    const b = this.backBtn;
    return data.x >= b.x && data.x <= b.x + b.w && data.y >= b.y && data.y <= b.y + b.h;
  }

  // BACKボタン描画（左上・全ゲーム共通）
  _drawBack() {
    const p = P();
    const b = this.backBtn;
    this.rect(b.x, b.y, b.w, b.h, p.dark);
    this.stroke(b.x, b.y, b.w, b.h, p.dim, 2);
    this.text('‹', b.x + b.w / 2, b.y + 4, 26, p.fg, 'center');
  }

  // ---- 描画ヘルパー（各ゲームから利用）----

  // ビットマップ風テキスト。align: 'left'|'center'|'right'
  text(str, x, y, size = 16, color = null, align = 'left') {
    const ctx = this.ctx;
    ctx.fillStyle = color || P().mid;
    ctx.font = `${size}px "DotGothic16", monospace`;
    ctx.textAlign = align;
    ctx.textBaseline = 'top';
    ctx.fillText(str, x, y);
  }

  // 角丸なしの矩形（塗り）
  rect(x, y, w, h, color) {
    this.ctx.fillStyle = color;
    this.ctx.fillRect(x, y, w, h);
  }

  // 枠線
  stroke(x, y, w, h, color, lw = 2) {
    const ctx = this.ctx;
    ctx.strokeStyle = color;
    ctx.lineWidth = lw;
    ctx.strokeRect(x, y, w, h);
  }
}


// ---- js/menu.js ----
// タイトル＆ゲーム選択メニュー。8本を2列グリッドで1画面に収める（スクロールなし）。

const COLS = 2;
const MARGIN = 16;
const GAP = 12;
const TILE_W = (W - MARGIN * 2 - GAP) / COLS;  // 158
const TILE_H = 96;
const TOP = 100;
const PITCH = TILE_H + 12;

class MenuScene extends Scene {
  constructor(engine, games) {
    super(engine);
    this.games = games;       // [{ meta, Game }]
    this.sel = 0;
    this.t = 0;
    this.isRoot = true;       // 最上位＝BACKボタン非表示
  }

  enter() {
    this.tiles = this._layout();
    this.themeIndex = this.games.length;
  }

  // 各タイル／テーマ行のヒット領域を計算
  _layout() {
    const tiles = [];
    this.games.forEach((g, i) => {
      const col = i % COLS, row = Math.floor(i / COLS);
      tiles.push({
        index: i,
        x: MARGIN + col * (TILE_W + GAP),
        y: TOP + row * PITCH,
        w: TILE_W, h: TILE_H,
      });
    });
    const rows = Math.ceil(this.games.length / COLS);
    this.themeRect = { x: MARGIN, y: TOP + rows * PITCH, w: W - MARGIN * 2, h: 34 };
    return tiles;
  }

  onInput(action, data) {
    const max = this.games.length; // = テーマ行のindex
    if (action === 'right') { this.sel = Math.min(this.sel + 1, max); this.engine.audio.select(); }
    else if (action === 'left') { this.sel = Math.max(this.sel - 1, 0); this.engine.audio.select(); }
    else if (action === 'down') { this.sel = Math.min(this.sel + COLS, max); this.engine.audio.select(); }
    else if (action === 'up') { this.sel = Math.max(this.sel - COLS, 0); this.engine.audio.select(); }
    else if (action === 'confirm') { this._activate(this.sel); }
    else if (action === 'tap') {
      for (const tile of this.tiles) {
        if (this._hit(tile, data)) { this._activate(tile.index); return; }
      }
      if (this._hit(this.themeRect, data)) { this._activate(this.themeIndex); }
    }
  }

  _hit(r, d) { return d.x >= r.x && d.x <= r.x + r.w && d.y >= r.y && d.y <= r.y + r.h; }

  _activate(i) {
    if (i < this.games.length) {
      this.engine.audio.good();
      this.engine.startGame(this.games[i]);
    } else {
      theme.current = theme.current === PALETTES.GREEN ? PALETTES.AMBER : PALETTES.GREEN;
      this.engine.audio.select();
    }
  }

  update(dt) { this.t += dt; }

  render(ctx) {
    const p = P();
    // タイトル
    this.engine.text('MICRO ARCADE', W / 2, 36, 30, p.mid, 'center');
    if (Math.floor(this.t * 2) % 2 === 0)
      this.engine.text('▼ SELECT GAME ▼', W / 2, 74, 12, p.dim, 'center');

    // ゲームタイル
    this.games.forEach((g, i) => {
      const tile = this.tiles[i];
      const on = this.sel === i;
      const cx = tile.x + tile.w / 2;
      this.engine.rect(tile.x, tile.y, tile.w, tile.h, on ? p.dark : p.bg);
      this.engine.stroke(tile.x, tile.y, tile.w, tile.h, on ? p.mid : p.dim, on ? 2 : 1);
      const hi = this.engine.storage.getHigh(g.meta.id);
      this.engine.text(g.meta.glyph || '?', cx, tile.y + 10, 30, on ? p.hi : p.mid, 'center');
      this.engine.text(g.meta.title, cx, tile.y + 50, 14, on ? p.hi : p.fg, 'center');
      this.engine.text('HI ' + hi, cx, tile.y + 72, 11, p.warn, 'center');
    });

    // テーマ切替
    const tr = this.themeRect;
    const ton = this.sel === this.themeIndex;
    if (ton) { this.engine.rect(tr.x, tr.y, tr.w, tr.h, p.dark); this.engine.stroke(tr.x, tr.y, tr.w, tr.h, p.mid, 2); }
    this.engine.text((ton ? '> ' : '') + 'THEME: ' + p.name, W / 2, tr.y + 9, 14, ton ? p.hi : p.mid, 'center');

    this.engine.text('TAP / SWIPE / ARROWS', W / 2, H - 24, 11, p.dim, 'center');
  }
}


// ---- js/games/rogue.js ----
(function(){
// 1-BIT HERO : 1画面ミニ・ローグライク
// @を動かして鍵Kを取り、出口Dへ。敵Eに触れると死亡。1プレイ数十秒、死んだら即リトライ。
// ★このファイルは「ゲーム実装の手本」。他ゲームも同じ形（meta + Game extends Scene）で作る。

const meta = {
  id: 'rogue',
  title: '1-BIT HERO',
  desc: '鍵を取り出口へ。敵を避けろ',
  glyph: '@',
};

const COLS = 9;
const ROWS = 12;
const CELL = 40;                 // 360 / 9
const GRID_Y = 96;               // グリッド開始Y（上にHUD）
const GRID_X = 0;

class Game extends Scene {
  enter() {
    this.score = 0;
    this.level = 1;
    this.high = this.engine.storage.getHigh(meta.id);
    this.dead = false;
    this.msg = 'SWIPE TO MOVE';
    this._build();
  }

  // レベル生成。到達可能性をBFSで保証する。
  _build() {
    const enemyCount = Math.min(1 + Math.floor(this.level / 2), 6);
    let tries = 0;
    do {
      tries++;
      this.walls = [];
      for (let y = 0; y < ROWS; y++) {
        this.walls[y] = [];
        for (let x = 0; x < COLS; x++) {
          // 外周は壁、内側はランダム
          const edge = (x === 0 || y === 0 || x === COLS - 1 || y === ROWS - 1);
          this.walls[y][x] = edge ? true : Math.random() < 0.20;
        }
      }
      this.player = { x: 1, y: ROWS - 2 };
      this.door = { x: COLS - 2, y: 1 };
      this.key = this._randFloor([this.player, this.door]);
      this.walls[this.player.y][this.player.x] = false;
      this.walls[this.door.y][this.door.x] = false;
      if (this.key) this.walls[this.key.y][this.key.x] = false;
    } while ((!this.key || !this._reachable(this.player, [this.key, this.door])) && tries < 40);

    // 敵配置（プレイヤーから離れた床）
    this.enemies = [];
    for (let i = 0; i < enemyCount; i++) {
      const e = this._randFloor([this.player, this.door, this.key, ...this.enemies], 4);
      if (e) this.enemies.push(e);
    }
    this.hasKey = false;
  }

  _randFloor(avoid = [], minDist = 0) {
    for (let t = 0; t < 100; t++) {
      const x = 1 + Math.floor(Math.random() * (COLS - 2));
      const y = 1 + Math.floor(Math.random() * (ROWS - 2));
      if (this.walls[y][x]) continue;
      let ok = true;
      for (const a of avoid) {
        if (!a) continue;
        if (a.x === x && a.y === y) { ok = false; break; }
        if (minDist && Math.abs(a.x - x) + Math.abs(a.y - y) < minDist) { ok = false; break; }
      }
      if (ok) return { x, y };
    }
    return null;
  }

  // startから targets 全てに到達できるか
  _reachable(start, targets) {
    const seen = new Set();
    const q = [start];
    seen.add(start.x + ',' + start.y);
    while (q.length) {
      const c = q.shift();
      for (const [dx, dy] of [[0,-1],[0,1],[-1,0],[1,0]]) {
        const nx = c.x + dx, ny = c.y + dy;
        if (nx < 0 || ny < 0 || nx >= COLS || ny >= ROWS) continue;
        if (this.walls[ny][nx]) continue;
        const k = nx + ',' + ny;
        if (seen.has(k)) continue;
        seen.add(k); q.push({ x: nx, y: ny });
      }
    }
    return targets.every(t => t && seen.has(t.x + ',' + t.y));
  }

  onInput(action) {
    if (this.dead) {
      if (action === 'tap' || action === 'confirm' || action === 'back') {
        if (action === 'back') return this.engine.toMenu();
        this.enter(); // リトライ
      }
      return;
    }
    if (action === 'back') return this.engine.toMenu();
    let dx = 0, dy = 0;
    if (action === 'up') dy = -1;
    else if (action === 'down') dy = 1;
    else if (action === 'left') dx = -1;
    else if (action === 'right') dx = 1;
    else return;
    this._step(dx, dy);
  }

  _step(dx, dy) {
    const nx = this.player.x + dx, ny = this.player.y + dy;
    if (this.walls[ny][nx]) { this.engine.audio.bad(); return; }
    this.player.x = nx; this.player.y = ny;
    this.engine.audio.move();

    // 鍵取得
    if (this.key && this.player.x === this.key.x && this.player.y === this.key.y) {
      this.hasKey = true; this.key = null; this.msg = 'GOT KEY! GO TO D';
      this.engine.audio.pick();
    }
    // 出口
    if (this.player.x === this.door.x && this.player.y === this.door.y) {
      if (this.hasKey) {
        this.score += 10 * this.level; this.level++;
        this.engine.audio.good(); this.msg = 'LEVEL ' + this.level;
        this._build(); return;
      } else { this.msg = 'NEED KEY!'; }
    }
    // 敵移動：検知範囲内ならプレイヤーを追跡、範囲外はランダム徘徊
    const detectRange = 4 + Math.floor(this.level / 3); // レベルが上がるほど検知範囲が広がる
    for (const e of this.enemies) {
      const dist = Math.abs(this.player.x - e.x) + Math.abs(this.player.y - e.y);
      if (dist <= detectRange) {
        // 追跡モード：X優先で1マス近づく
        const ex = e.x + Math.sign(this.player.x - e.x);
        const ey = e.y + Math.sign(this.player.y - e.y);
        if (!this.walls[e.y][ex] && ex !== e.x) e.x = ex;
        else if (!this.walls[ey][e.x] && ey !== e.y) e.y = ey;
      } else {
        // 徘徊モード：ランダムな直交方向に1マス移動（25%で停止）
        if (Math.random() < 0.25) continue; // 止まる
        const dirs = [[0,-1],[0,1],[-1,0],[1,0]];
        // シャッフル
        for (let i = dirs.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [dirs[i], dirs[j]] = [dirs[j], dirs[i]];
        }
        for (const [ddx, ddy] of dirs) {
          const nx = e.x + ddx, ny = e.y + ddy;
          if (nx >= 0 && ny >= 0 && nx < COLS && ny < ROWS && !this.walls[ny][nx]) {
            e.x = nx; e.y = ny; break;
          }
        }
      }
    }
    this._checkDeath();
  }

  _checkDeath() {
    for (const e of this.enemies) {
      if (e.x === this.player.x && e.y === this.player.y) {
        this.dead = true;
        this.engine.audio.bad();
        if (this.engine.storage.setHigh(meta.id, this.score)) this.high = this.score;
        this.msg = 'YOU DIED';
        return;
      }
    }
  }

  render(ctx) {
    const p = P();
    // HUD（左上はBACKボタンが x:6..48 を占有するため x>=52 から描く）
    this.engine.text('1-BIT HERO', 52, 14, 18, p.fg, 'left');
    this.engine.text('LV ' + this.level, W - 12, 14, 16, p.fg, 'right');
    this.engine.text('SCORE ' + this.score, 52, 44, 14, p.mid, 'left');
    this.engine.text('HI ' + this.high, W - 12, 44, 14, p.dim, 'right');

    // グリッド
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        const px = GRID_X + x * CELL, py = GRID_Y + y * CELL;
        if (this.walls[y][x]) {
          this.engine.rect(px + 2, py + 2, CELL - 4, CELL - 4, p.dark);
          this.engine.text('#', px + CELL / 2, py + 8, 22, p.dim, 'center');
        }
      }
    }
    const glyph = (gx, gy, ch, color) =>
      this.engine.text(ch, GRID_X + gx * CELL + CELL / 2, GRID_Y + gy * CELL + 6, 26, color, 'center');

    if (this.key) glyph(this.key.x, this.key.y, 'K', p.warn);
    glyph(this.door.x, this.door.y, 'D', this.hasKey ? p.fg : p.dim);
    for (const e of this.enemies) glyph(e.x, e.y, 'E', p.bad);
    glyph(this.player.x, this.player.y, '@', p.hi);

    // フッターメッセージ
    this.engine.text(this.msg, W / 2, H - 56, 16, p.fg, 'center');

    if (this.dead) {
      this.engine.rect(0, H / 2 - 70, W, 140, p.dark);
      this.engine.text('YOU DIED', W / 2, H / 2 - 50, 32, p.bad, 'center');
      this.engine.text('SCORE ' + this.score, W / 2, H / 2 - 6, 18, p.fg, 'center');
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 28, 14, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/binary.js ----
(function(){
// BINARY : 2進数タイムアタック
// 目標の10進数を6ビットで作れ！タップでビットを切り替え、一致したらクリア。
// タイマーが尽きる前にできるだけ多くの目標をクリアせよ。

const meta = {
  id: 'binary',
  title: 'BINARY',
  desc: '目標の数を2進数で作れ',
  glyph: '01',
};

// ---- 定数 ----
const BITS       = 6;                    // ビット数（最大63）
const PLACE_VAL  = [32, 16, 8, 4, 2, 1]; // 左から右へ

const INIT_TIME  = 16;                   // 初期タイマー（秒）— より余裕を持たせる
const ADD_TIME   = 5;                    // 正解時に追加する秒数（増量）
const TIME_CAP   = 30;                   // タイマー上限（秒）— 連続正解でも30秒まで

// HUDとレイアウト
const HUD_H      = 90;                   // HUD高さ
const TARGET_Y   = 98;                   // "TARGET" ラベル Y
const TARGET_NUM_Y = 122;                // 目標数字 Y
const EQUALS_Y   = 230;                  // "= XX" 表示 Y
const BITS_Y     = 280;                  // ビットボックス行 Y
const TIMER_BAR_Y = 560;                 // タイマーバー Y
const TIMER_BAR_H = 18;                  // タイマーバー高さ

// ビットボックス: 6個を横幅360にフィット。左右マージンを最小にする。
const BOX_W      = 52;
const BOX_H      = 72;
const BOX_GAP    = 4;
const BOX_ROW_W  = BOX_W * BITS + BOX_GAP * (BITS - 1); // 52*6 + 4*5 = 332
const BOX_X0     = Math.round((W - BOX_ROW_W) / 2);     // 14

// ---- ユーティリティ ----
function randTarget(exclude) {
  // 1..63 からexcludeを除いてランダムに選ぶ
  let v;
  do { v = 1 + Math.floor(Math.random() * 63); } while (v === exclude);
  return v;
}

function bitsToDecimal(bits) {
  let n = 0;
  for (let i = 0; i < BITS; i++) n += bits[i] * PLACE_VAL[i];
  return n;
}

// ---- ゲームクラス ----
class Game extends Scene {
  enter() {
    this.score    = 0;
    this.level    = 1;
    this.high     = this.engine.storage.getHigh(meta.id);
    this.over     = false;
    this.timer    = INIT_TIME;
    this.bits     = new Array(BITS).fill(0);  // 全ビット0
    this.target   = randTarget(-1);           // 最初の目標
    this.cursor   = 0;                        // キーボード用カーソル（左右で移動）
    this.flash    = 0;                        // 正解フラッシュ残り時間（秒）
  }

  // ---- ロジック ----
  update(dt) {
    if (this.over) return;

    // フラッシュカウントダウン
    if (this.flash > 0) this.flash -= dt;

    // タイマーカウントダウン
    this.timer -= dt;
    if (this.timer <= 0) {
      this.timer = 0;
      this._gameOver();
    }
  }

  _toggleBit(i) {
    this.bits[i] ^= 1;
    this.engine.audio.beep(this.bits[i] ? 880 : 440, 0.06, 'square', 0.18);
    this._checkMatch();
  }

  _checkMatch() {
    if (bitsToDecimal(this.bits) === this.target) {
      this.engine.audio.good();
      this.score += this.level;
      this.level++;
      // タイマー追加（上限あり）
      this.timer = Math.min(this.timer + ADD_TIME, TIME_CAP);
      // フラッシュ演出
      this.flash = 0.35;
      // 新しい目標、ビットをリセット
      this.target = randTarget(this.target);
      this.bits.fill(0);
      // ハイスコア更新
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }
    }
  }

  _gameOver() {
    this.over = true;
    this.engine.audio.bad();
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- 入力 ----
  onInput(action, data) {
    if (this.over) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap') {
      // どのビットボックスをタップしたか判定
      const tx = data.x;
      const ty = data.y;
      for (let i = 0; i < BITS; i++) {
        const bx = BOX_X0 + i * (BOX_W + BOX_GAP);
        const by = BITS_Y;
        if (tx >= bx && tx <= bx + BOX_W && ty >= by && ty <= by + BOX_H) {
          this._toggleBit(i);
          return;
        }
      }
      return;
    }

    // キーボード: 左右でカーソル移動、confirm/up/downでトグル
    if (action === 'left') {
      this.cursor = (this.cursor - 1 + BITS) % BITS;
      this.engine.audio.move();
      return;
    }
    if (action === 'right') {
      this.cursor = (this.cursor + 1) % BITS;
      this.engine.audio.move();
      return;
    }
    if (action === 'confirm' || action === 'up' || action === 'down') {
      this._toggleBit(this.cursor);
      return;
    }
  }

  // ---- 描画 ----
  render(ctx) {
    const p = P();

    // ---------- HUD ----------
    this.engine.text('BINARY', 52, 12, 20, p.fg, 'left');  // BACKボタン(~x48)の右から開始
    this.engine.text('LV ' + this.level, W - 12, 12, 16, p.fg, 'right');
    this.engine.text('SCORE ' + this.score, 52, 42, 14, p.mid, 'left');
    this.engine.text('HI ' + this.high, W - 12, 42, 14, p.dim, 'right');

    // HUD区切り線
    this.engine.rect(0, HUD_H - 2, W, 2, p.dark);

    // ---------- 目標表示 ----------
    this.engine.text('TARGET', W / 2, TARGET_Y, 14, p.dim, 'center');

    // 正解フラッシュ: 目標数字をhi色で強調
    const targetColor = (this.flash > 0) ? p.hi : p.warn;
    this.engine.text('' + this.target, W / 2, TARGET_NUM_Y, 64, targetColor, 'center');

    // ---------- ビットボックス ----------
    const currentVal = bitsToDecimal(this.bits);

    for (let i = 0; i < BITS; i++) {
      const bx = BOX_X0 + i * (BOX_W + BOX_GAP);
      const by = BITS_Y;
      const isOn = this.bits[i] === 1;
      const isCursor = (i === this.cursor);

      // ボックス背景
      const boxBg = isOn ? p.dim : p.dark;
      this.engine.rect(bx, by, BOX_W, BOX_H, boxBg);

      // カーソル枠（キーボード用）
      const borderColor = isCursor ? p.fg : (isOn ? p.mid : p.dim);
      const borderWidth = isCursor ? 3 : 2;
      this.engine.stroke(bx, by, BOX_W, BOX_H, borderColor, borderWidth);

      // ビット値（0 or 1）
      const bitColor = isOn ? p.hi : p.dim;
      this.engine.text('' + this.bits[i], bx + BOX_W / 2, by + 12, 28, bitColor, 'center');

      // 桁の重み（小さく下に）
      this.engine.text('' + PLACE_VAL[i], bx + BOX_W / 2, by + BOX_H - 20, 12, p.dim, 'center');
    }

    // ---------- 現在値 = XX ----------
    const eqColor = (currentVal === this.target) ? p.hi : p.fg;
    this.engine.text('= ' + currentVal, W / 2, EQUALS_Y, 30, eqColor, 'center');

    // 一致ヒント矢印
    if (currentVal === this.target && !this.over) {
      this.engine.text('OK!', W / 2, EQUALS_Y + 36, 16, p.hi, 'center');
    }

    // ---------- タイマーバー ----------
    const ratio = this.timer / INIT_TIME;       // 0..1 以上になる場合もあるのでclamp
    const clampedRatio = Math.min(1, Math.max(0, ratio));
    const barMaxW = W - 24;                     // 左右12pxマージン

    // バー背景
    this.engine.rect(12, TIMER_BAR_Y, barMaxW, TIMER_BAR_H, p.dark);

    // バー本体（残り時間に応じて色を変える）
    let barColor = p.mid;
    if (clampedRatio < 0.25) barColor = p.bad;
    else if (clampedRatio < 0.5) barColor = p.warn;
    const barW = Math.round(barMaxW * clampedRatio);
    if (barW > 0) this.engine.rect(12, TIMER_BAR_Y, barW, TIMER_BAR_H, barColor);

    // バー枠線
    this.engine.stroke(12, TIMER_BAR_Y, barMaxW, TIMER_BAR_H, p.dim, 1);

    // タイマー数値
    const timerLabel = this.timer.toFixed(1);
    this.engine.text(timerLabel, W / 2, TIMER_BAR_Y - 22, 16, barColor, 'center');

    // ---------- ゲームオーバーオーバーレイ ----------
    if (this.over) {
      // 半透明背景（bg色で塗りつぶし）
      this.engine.rect(0, H / 2 - 90, W, 180, p.dark);
      this.engine.stroke(12, H / 2 - 90, W - 24, 180, p.dim, 2);

      this.engine.text('GAME OVER', W / 2, H / 2 - 68, 32, p.bad, 'center');
      this.engine.text('SCORE ' + this.score, W / 2, H / 2 - 24, 20, p.fg, 'center');
      if (this.score === this.high && this.score > 0) {
        this.engine.text('NEW RECORD!', W / 2, H / 2 + 10, 16, p.warn, 'center');
      }
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 42, 14, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/hack.js ----
(function(){
// HACK : コードブレーカー × リアクションスピード
// グリッドから「DECRYPT」ターゲットを見つけてタップせよ。
// 全10ラウンド固定。タイムアウトなし。反応速度でスコアを競う。
// 速くタップするほど高得点。誤タップは減点なし（時間ロスで自然にスコアが下がる）。

const meta = {
  id: 'hack',
  title: 'HACK',
  desc: '一致コードを素早くタップ',
  glyph: '#',
};

// ---- レイアウト定数 ----
const COLS        = 4;           // グリッド列数
const ROWS        = 5;           // グリッド行数（20セル固定）
const CELL_W      = 84;          // セル幅  (360 / 4 = 90 → 余白込みで84)
const CELL_H      = 60;          // セル高さ
const GRID_X      = 12;          // グリッド左端
const GRID_Y      = 210;         // グリッド上端（HUDの下）
const CELL_GAP_X  = 6;           // 横間隔
const CELL_GAP_Y  = 6;           // 縦間隔

// ---- ゲームパラメータ ----
const TOTAL_ROUNDS  = 10;        // 全ラウンド数（固定）
const FLASH_DUR     = 0.22;      // フラッシュ持続秒
const SCORE_MAX     = 1000;      // 1ラウンドの最高得点
const SCORE_MIN     = 50;        // 1ラウンドの最低得点（どんなに遅くても）
// 反応時間スコア計算: score = max(SCORE_MIN, SCORE_MAX - elapsed * SCORE_DECAY)
// 例) 0秒→1000点、5秒→500点、10秒以上→50点
const SCORE_DECAY   = 95;        // 1秒あたりの減点量
const FLASH_GAIN_DUR = 0.7;      // "+NNN" 表示の持続秒

// 16進コード生成に使う文字
const HEX_CHARS = '0123456789ABCDEF';

// バックグラウンドに流す片仮名ノイズ文字（ハッカー演出）
const NOISE_CHARS = 'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホ0123456789ABCDEF';
const NOISE_COUNT = 30;

// ランダム 2文字 hex コード
function randCode() {
  return HEX_CHARS[Math.floor(Math.random() * 16)] +
         HEX_CHARS[Math.floor(Math.random() * 16)];
}

class Game extends Scene {
  enter() {
    this.score      = 0;           // 累計スコア
    this.round      = 0;           // 現在ラウンド（0始まり、TOTAL_ROUNDSで終了）
    this.high       = this.engine.storage.getHigh(meta.id);
    this.over       = false;       // リザルト画面フラグ
    this.elapsed    = 0;           // 現在ラウンドの経過時間（秒）

    // フラッシュ状態 { idx, t, good }
    this.flash      = null;

    // "+NNN" 得点フラッシュ { text, t }
    this.gainFlash  = null;

    // ノイズ粒子
    this._initNoise();

    // 最初のラウンド開始
    this._newRound();
  }

  // ---- ノイズ粒子初期化 ----
  _initNoise() {
    this.noise = [];
    for (let i = 0; i < NOISE_COUNT; i++) {
      this.noise.push(this._makeNoisePart());
    }
  }

  _makeNoisePart() {
    return {
      x: Math.random() * W,
      y: Math.random() * H,
      ch: NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)],
      speed: 18 + Math.random() * 40,   // px/s
      age: Math.random() * 4,
    };
  }

  // ---- グリッド生成（ターゲットがグリッド内に必ず1つ） ----
  _newRound() {
    // 全セルにユニークコードを割り当てる（ターゲット重複を防ぐため）
    const total = COLS * ROWS;
    const used = new Set();
    const codes = [];
    while (codes.length < total) {
      const c = randCode();
      if (!used.has(c)) { used.add(c); codes.push(c); }
    }

    // ターゲットはコード一覧からランダムに1つ選ぶ
    const targetIdx = Math.floor(Math.random() * total);
    this.target = codes[targetIdx];

    // セルオブジェクト生成（x,y,w,h,code）
    this.cells = [];
    for (let row = 0; row < ROWS; row++) {
      for (let col = 0; col < COLS; col++) {
        const idx = row * COLS + col;
        const cx = GRID_X + col * (CELL_W + CELL_GAP_X);
        const cy = GRID_Y + row * (CELL_H + CELL_GAP_Y);
        this.cells.push({
          x: cx, y: cy, w: CELL_W, h: CELL_H,
          code: codes[idx],
        });
      }
    }

    // 経過タイマーをリセット
    this.elapsed = 0;

    // タイピング演出: ターゲット表示を1文字ずつ
    this._typeLen   = 0;
    this._typeTimer = 0;
    this._typeDone  = false;
  }

  // ---- update ----
  update(dt) {
    if (this.over) return;

    // 現在ラウンドの経過時間（タイムアウトなし、スコア計算用）
    this.elapsed += dt;

    // フラッシュ
    if (this.flash) {
      this.flash.t -= dt;
      if (this.flash.t <= 0) this.flash = null;
    }

    // 得点フラッシュ
    if (this.gainFlash) {
      this.gainFlash.t -= dt;
      if (this.gainFlash.t <= 0) this.gainFlash = null;
    }

    // ノイズアニメーション（下方向スクロール）
    for (const part of this.noise) {
      part.y += part.speed * dt;
      part.age += dt;
      if (part.y > H + 20) {
        part.y = -20;
        part.x = Math.random() * W;
        part.ch = NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)];
      }
      // 約5秒ごとに文字を変える
      if (part.age > 5) {
        part.age = 0;
        part.ch = NOISE_CHARS[Math.floor(Math.random() * NOISE_CHARS.length)];
      }
    }

    // タイピング演出（1文字 0.06s）
    if (!this._typeDone) {
      this._typeTimer += dt;
      const targetLen = ('DECRYPT > ' + this.target).length;
      this._typeLen = Math.min(Math.floor(this._typeTimer / 0.06), targetLen);
      if (this._typeLen >= targetLen) this._typeDone = true;
    }
  }

  // ---- onInput ----
  onInput(action, data) {
    if (this.over) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') { this.enter(); }
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap' && data) {
      this._handleTap(data.x, data.y);
    }
  }

  _handleTap(tx, ty) {
    // どのセルがタップされたか
    const idx = this.cells.findIndex(
      c => tx >= c.x && tx < c.x + c.w && ty >= c.y && ty < c.y + c.h
    );
    if (idx < 0) return; // セル外

    const cell = this.cells[idx];
    if (cell.code === this.target) {
      // 正解 — 反応時間でスコア計算
      const gain = Math.max(SCORE_MIN, Math.round(SCORE_MAX - this.elapsed * SCORE_DECAY));
      this.score += gain;
      this.flash = { idx, t: FLASH_DUR, good: true };
      this.gainFlash = { text: '+' + gain, t: FLASH_GAIN_DUR };
      this.engine.audio.good();

      // ハイスコア更新
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }

      this.round++;
      if (this.round >= TOTAL_ROUNDS) {
        // 全ラウンド終了 → リザルト
        this._showResults();
      } else {
        // 次ラウンドへ
        this._newRound();
      }
    } else {
      // 不正解 — ゲーム終了なし。赤フラッシュのみ（経過時間は止まらない）
      this.flash = { idx, t: FLASH_DUR, good: false };
      this.engine.audio.bad();
    }
  }

  _showResults() {
    this.over = true;
    // 最終スコアでハイスコア更新（正解時にも更新しているが念のため）
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- render ----
  render(ctx) {
    const p = P();

    // ---- ノイズ背景（dimカラー、グリッドの下に描画）----
    for (const n of this.noise) {
      const inGrid = n.x >= GRID_X && n.x < GRID_X + COLS * (CELL_W + CELL_GAP_X) &&
                     n.y >= GRID_Y && n.y < GRID_Y + ROWS * (CELL_H + CELL_GAP_Y);
      ctx.globalAlpha = inGrid ? 0.07 : 0.18;
      this.engine.text(n.ch, n.x, n.y, 12, p.dim, 'center');
      ctx.globalAlpha = 1.0;
    }

    // ---- HUD ----
    // タイトルバー（BACKボタンは x:6..48 なので HACK タイトルは x>=52 から）
    this.engine.rect(0, 0, W, 44, p.dark);
    this.engine.text('HACK', 52, 10, 22, p.fg, 'left');   // BACKボタン右側から開始
    this.engine.text('HI ' + this.high, W - 14, 10, 16, p.dim, 'right');

    // スコア行
    this.engine.text('SCORE', 52, 52, 13, p.dim, 'left');
    this.engine.text(String(this.score), 52, 68, 26, p.mid, 'left');

    // ラウンド進捗（右側）
    const roundDisp = Math.min(this.round + 1, TOTAL_ROUNDS);
    this.engine.text('ROUND ' + roundDisp + ' / ' + TOTAL_ROUNDS, W - 14, 52, 13, p.dim, 'right');

    // 経過時間（右側。反応速度の参考表示）
    const elapsedLabel = this.elapsed.toFixed(1) + 's';
    this.engine.text(elapsedLabel, W - 14, 68, 20, p.fg, 'right');

    // ---- DECRYPT ターゲット ----
    this.engine.rect(0, 145, W, 56, p.dark);
    this.engine.stroke(0, 145, W, 56, p.dim, 1);
    const fullLabel = 'DECRYPT > ' + this.target;
    const showLabel = this._typeDone ? fullLabel : fullLabel.slice(0, this._typeLen);
    // カーソル点滅（タイピング中）
    const cursor = (!this._typeDone && Math.floor(Date.now() / 250) % 2 === 0) ? '_' : '';
    this.engine.text(showLabel + cursor, W / 2, 157, 24, p.hi, 'center');

    // ---- グリッドセル ----
    for (let i = 0; i < this.cells.length; i++) {
      const c = this.cells[i];
      const isFlash = this.flash && this.flash.idx === i;

      let bgColor = p.dark;
      let textColor = p.fg;
      let borderColor = p.dim;

      if (isFlash) {
        if (this.flash.good) {
          bgColor = p.mid;
          textColor = p.bg;
          borderColor = p.hi;
        } else {
          bgColor = p.bad;
          textColor = p.hi;
          borderColor = p.bad;
        }
      }

      this.engine.rect(c.x, c.y, c.w, c.h, bgColor);
      this.engine.stroke(c.x, c.y, c.w, c.h, borderColor, 1);
      this.engine.text(c.code, c.x + c.w / 2, c.y + c.h / 2 - 12, 22, textColor, 'center');
    }

    // ---- "+NNN" 得点フラッシュ（グリッド上部に表示）----
    if (this.gainFlash) {
      const alpha = Math.min(1, this.gainFlash.t / FLASH_GAIN_DUR * 2);
      ctx.globalAlpha = alpha;
      this.engine.text(this.gainFlash.text, W / 2, GRID_Y - 30, 28, p.warn, 'center');
      ctx.globalAlpha = 1.0;
    }

    // ---- リザルトオーバーレイ ----
    if (this.over) {
      // 半透明の暗幕
      ctx.globalAlpha = 0.88;
      this.engine.rect(0, 0, W, H, p.bg);
      ctx.globalAlpha = 1.0;

      // ボックス
      const bx = 24, by = H / 2 - 140, bw = W - 48, bh = 280;
      this.engine.rect(bx, by, bw, bh, p.dark);
      this.engine.stroke(bx, by, bw, bh, p.mid, 2);

      this.engine.text('MISSION COMPLETE', W / 2, by + 18, 20, p.mid, 'center');
      this.engine.text('TOTAL SCORE', W / 2, by + 60, 14, p.dim, 'center');
      this.engine.text(String(this.score), W / 2, by + 78, 48, p.hi, 'center');

      // ハイスコア表示
      if (this.score >= this.high && this.score > 0) {
        this.engine.text('NEW RECORD!', W / 2, by + 140, 18, p.warn, 'center');
      } else {
        this.engine.text('HI  ' + this.high, W / 2, by + 140, 16, p.dim, 'center');
      }

      // スコア解説（最高・達成ラウンド）
      this.engine.text(TOTAL_ROUNDS + ' ROUNDS CLEARED', W / 2, by + 170, 14, p.fg, 'center');
      this.engine.text('MAX ' + (SCORE_MAX * TOTAL_ROUNDS) + ' PTS POSSIBLE', W / 2, by + 192, 12, p.dim, 'center');

      this.engine.text('TAP TO RETRY', W / 2, by + 236, 15, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/snake.js ----
(function(){
// SNAKE : CRTグリーンの定番スネークゲーム
// スワイプで方向操作。食べ物を食べて成長、壁か自分の体に当たったらゲームオーバー。

const meta = {
  id: 'snake',
  title: 'SNAKE',
  desc: 'CRTグリーンの定番スネーク',
  glyph: '~',
};

// ---- グリッド設定 ----
// COLS=12, ROWS=16, CELL=30 → プレイエリア 360x480
// HUD: 0〜95px, プレイエリア: 96〜575px（480px）, フッター: 576〜639px（64px）
const COLS = 12;
const ROWS = 16;
const CELL = 30;
const GRID_X = 0;
const GRID_Y = 96;

// ---- ゲームパラメータ ----
const STEP_INIT = 0.22;    // 初期ステップ間隔（秒）：ゆっくりスタート
const STEP_FLOOR = 0.10;   // 最高速度（秒）：速くなりすぎない上限
const SPEED_UP = 0.004;    // 食べるたびに間隔を縮める量（緩やかに加速）

class Game extends Scene {
  enter() {
    this.score = 0;
    this.high = this.engine.storage.getHigh(meta.id);
    this.dead = false;

    // スネーク初期化：中央付近から右向きに3マス
    const startX = Math.floor(COLS / 2);
    const startY = Math.floor(ROWS / 2);
    // bodyは頭から尻尾の順（インデックス0が頭）
    this.body = [
      { x: startX,     y: startY },
      { x: startX - 1, y: startY },
      { x: startX - 2, y: startY },
    ];
    this.dir = { x: 1, y: 0 };  // 右向きで開始

    // 入力バッファ（最大2手先まで）：素早いスワイプを取りこぼさない
    this.dirBuffer = [];

    // ステップタイマー（最初の入力があるまで動かない猶予）
    this.stepInterval = STEP_INIT;
    this.stepTimer = 0;
    this.waitingForFirst = true; // 最初の入力待ち猶予フラグ

    // 食べ物を配置
    this.food = this._spawnFood();
  }

  // ---- 空きセルにランダムに食べ物を置く ----
  _spawnFood() {
    // スネークが占有しているセルのセットを作成
    const occupied = new Set(this.body.map(s => s.x + ',' + s.y));
    const candidates = [];
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        if (!occupied.has(x + ',' + y)) candidates.push({ x, y });
      }
    }
    if (candidates.length === 0) return null; // 盤面が満杯（クリア）
    return candidates[Math.floor(Math.random() * candidates.length)];
  }

  // ---- 入力処理 ----
  onInput(action, data) {
    // ゲームオーバー中
    if (this.dead) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    // 方向入力をバッファに積む（バッファは最大2個まで：素早い連続スワイプに対応）
    let nd = null;
    if (action === 'up')    nd = { x: 0,  y: -1 };
    else if (action === 'down')  nd = { x: 0,  y: 1  };
    else if (action === 'left')  nd = { x: -1, y: 0  };
    else if (action === 'right') nd = { x: 1,  y: 0  };

    if (nd && this.dirBuffer.length < 2) {
      // バッファの末尾（次に適用される方向）に対して直逆でないか事前チェック
      const prev = this.dirBuffer.length > 0
        ? this.dirBuffer[this.dirBuffer.length - 1]
        : this.dir;
      const isReverse = (nd.x !== 0 && nd.x === -prev.x) ||
                        (nd.y !== 0 && nd.y === -prev.y);
      if (!isReverse) {
        this.dirBuffer.push(nd);
        if (this.waitingForFirst) this.waitingForFirst = false; // 猶予終了
      }
    }
  }

  // ---- 毎フレーム更新 ----
  update(dt) {
    if (this.dead) return;
    // 最初の入力待ち中はタイマーを進めない（プレイヤーが準備できるまで待機）
    if (this.waitingForFirst) return;

    this.stepTimer += dt;
    if (this.stepTimer >= this.stepInterval) {
      this.stepTimer -= this.stepInterval;
      this._step();
    }
  }

  // ---- 1ステップ進める ----
  _step() {
    // バッファから次の方向を適用（直逆はバッファ投入時に除外済み）
    if (this.dirBuffer.length > 0) {
      this.dir = this.dirBuffer.shift();
    }

    // 新しい頭の位置を計算
    const head = this.body[0];
    const nx = head.x + this.dir.x;
    const ny = head.y + this.dir.y;

    // 壁衝突判定
    if (nx < 0 || ny < 0 || nx >= COLS || ny >= ROWS) {
      this._die();
      return;
    }

    // 自己衝突判定（尻尾は移動後に消えるので除外して判定）
    // 尻尾以外のセルと衝突したら死亡
    for (let i = 0; i < this.body.length - 1; i++) {
      if (this.body[i].x === nx && this.body[i].y === ny) {
        this._die();
        return;
      }
    }

    // 食べ物判定
    const ate = this.food && nx === this.food.x && ny === this.food.y;

    // スネークを前進させる：先頭に追加
    this.body.unshift({ x: nx, y: ny });

    if (ate) {
      // 成長：尻尾を消さない
      this.score += 1;
      this.engine.audio.pick();
      // 速度アップ（下限あり）
      this.stepInterval = Math.max(STEP_FLOOR, this.stepInterval - SPEED_UP);
      // 新しい食べ物を配置
      this.food = this._spawnFood();
      // ハイスコア更新チェック
      if (this.engine.storage.setHigh(meta.id, this.score)) {
        this.high = this.score;
      }
    } else {
      // 通常移動：尻尾を削除
      this.body.pop();
    }
  }

  // ---- 死亡処理 ----
  _die() {
    this.dead = true;
    this.engine.audio.bad();
    if (this.engine.storage.setHigh(meta.id, this.score)) {
      this.high = this.score;
    }
  }

  // ---- 描画 ----
  render(ctx) {
    const p = P();

    // ---- HUD（左上はBACKボタンが x:6..48 を占有するため x>=52 から描く）----
    this.engine.text('SNAKE', 52, 12, 20, p.fg, 'left');
    this.engine.text('HI ' + this.high, W - 12, 12, 14, p.dim, 'right');
    this.engine.text('SCORE', 52, 44, 13, p.dim, 'left');
    this.engine.text(String(this.score), 52, 62, 22, p.mid, 'left');

    // ---- プレイフィールドの背景 ----
    this.engine.rect(GRID_X, GRID_Y, COLS * CELL, ROWS * CELL, p.dark);

    // ---- グリッドドット（薄い格子点） ----
    ctx.fillStyle = p.dim;
    for (let y = 1; y < ROWS; y++) {
      for (let x = 1; x < COLS; x++) {
        const px = GRID_X + x * CELL;
        const py = GRID_Y + y * CELL;
        ctx.fillRect(px - 1, py - 1, 2, 2);
      }
    }

    // ---- 食べ物 ----
    if (this.food) {
      const fx = GRID_X + this.food.x * CELL;
      const fy = GRID_Y + this.food.y * CELL;
      // 食べ物：明るい黄色で塗り、内側に小さい正方形
      this.engine.rect(fx + 4, fy + 4, CELL - 8, CELL - 8, p.warn);
      this.engine.rect(fx + 8, fy + 8, CELL - 16, CELL - 16, p.hi);
    }

    // ---- スネーク本体 ----
    for (let i = this.body.length - 1; i >= 0; i--) {
      const seg = this.body[i];
      const px = GRID_X + seg.x * CELL;
      const py = GRID_Y + seg.y * CELL;

      if (i === 0) {
        // 頭：ハイライトカラー + やや大きめ
        this.engine.rect(px + 1, py + 1, CELL - 2, CELL - 2, p.hi);
        // 頭の目（進行方向に応じて表示）
        ctx.fillStyle = p.dark;
        const eyeSize = 4;
        if (this.dir.x === 1) {
          // 右向き：右側に目
          ctx.fillRect(px + CELL - 8, py + 5,   eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 8, py + CELL - 9, eyeSize, eyeSize);
        } else if (this.dir.x === -1) {
          // 左向き：左側に目
          ctx.fillRect(px + 4, py + 5,   eyeSize, eyeSize);
          ctx.fillRect(px + 4, py + CELL - 9, eyeSize, eyeSize);
        } else if (this.dir.y === -1) {
          // 上向き：上側に目
          ctx.fillRect(px + 5,        py + 4, eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 9, py + 4, eyeSize, eyeSize);
        } else {
          // 下向き：下側に目
          ctx.fillRect(px + 5,        py + CELL - 8, eyeSize, eyeSize);
          ctx.fillRect(px + CELL - 9, py + CELL - 8, eyeSize, eyeSize);
        }
      } else {
        // 胴体：末尾に近いほど暗く
        const ratio = i / (this.body.length - 1); // 0(首)→1(尻尾)
        // 首に近い→p.fg、尻尾に近い→p.mid
        const color = ratio < 0.5 ? p.fg : p.mid;
        const pad = 2 + Math.floor(ratio * 3); // 尻尾ほど細く
        this.engine.rect(px + pad, py + pad, CELL - pad * 2, CELL - pad * 2, color);
      }
    }

    // ---- フィールドの枠線 ----
    this.engine.stroke(GRID_X, GRID_Y, COLS * CELL, ROWS * CELL, p.dim, 2);

    // ---- フッター：操作ヒント ----
    if (!this.dead) {
      this.engine.text('SWIPE TO STEER', W / 2, GRID_Y + ROWS * CELL + 16, 13, p.dim, 'center');
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.dead) {
      // 半透明の暗いオーバーレイ
      ctx.fillStyle = p.dark;
      ctx.globalAlpha = 0.88;
      ctx.fillRect(0, H / 2 - 90, W, 180);
      ctx.globalAlpha = 1.0;

      this.engine.stroke(16, H / 2 - 90, W - 32, 180, p.dim, 2);
      this.engine.text('GAME OVER', W / 2, H / 2 - 72, 28, p.bad, 'center');
      this.engine.text('SCORE  ' + this.score, W / 2, H / 2 - 30, 20, p.fg, 'center');
      if (this.score > 0 && this.score === this.high) {
        this.engine.text('NEW BEST!', W / 2, H / 2 + 4, 16, p.warn, 'center');
      }
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 36, 16, p.mid, 'center');
      this.engine.text('BACK = MENU', W / 2, H / 2 + 62, 13, p.dim, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/beeper.js ----
(function(){
// BEEPER : サイモン風記憶ゲーム
// 光る順番を記憶してパッドを同じ順番でタップ。ラウンドが進むほど長くなる。
// フレームレート非依存の update(dt) ステートマシンで再生アニメを制御する。

const meta = {
  id: 'beeper',
  title: 'BEEPER',
  desc: '光る順番を記憶して再現',
  glyph: '♪',
};

// ---- パッド定義 ----
// 2×2 グリッド。各パッドに固有の色と音程を割り当てる。
const PAD_SIZE  = 130;  // パッドの一辺の長さ (px)
const PAD_GAP   = 14;   // パッド間の隙間 (px)
const PAD_LEFT  = (W - PAD_SIZE * 2 - PAD_GAP) / 2; // グリッド左端 X
const PAD_TOP   = 180;  // グリッド上端 Y（HUDの下）

// パッド 0=左上, 1=右上, 2=左下, 3=右下
const PADS = [
  { col: 0, row: 0, freq: 330 },   // 左上: E4 寄り
  { col: 1, row: 0, freq: 415 },   // 右上: Ab4 寄り
  { col: 0, row: 1, freq: 494 },   // 左下: B4 寄り
  { col: 1, row: 1, freq: 622 },   // 右下: Eb5 寄り
];

// パッドの明暗に使うパレットインデックス（パッド番号→明色・暗色）
// パレットから 4 色選ぶ：mid, warn, bad, fg
const PAD_BRIGHT = ['mid', 'warn', 'bad', 'fg'];   // 点灯時
const PAD_DIM    = ['dark', 'dark', 'dark', 'dark']; // 消灯時 (どれも dark)

// パッド座標を計算する
function padRect(i) {
  const { col, row } = PADS[i];
  const x = PAD_LEFT + col * (PAD_SIZE + PAD_GAP);
  const y = PAD_TOP  + row * (PAD_SIZE + PAD_GAP);
  return { x, y, w: PAD_SIZE, h: PAD_SIZE };
}

// タップ座標がどのパッドに当たるか。当たらなければ -1
function hitPad(tx, ty) {
  for (let i = 0; i < 4; i++) {
    const { x, y, w, h } = padRect(i);
    if (tx >= x && tx <= x + w && ty >= y && ty <= y + h) return i;
  }
  return -1;
}

// ---- ゲーム内部の状態定数 ----
const STATE_SHOW    = 'SHOW';   // コンピュータが再生中
const STATE_INPUT   = 'INPUT';  // プレイヤーが入力中
const STATE_PAUSE   = 'PAUSE';  // ラウンド正解後のブリーフポーズ
const STATE_OVER    = 'OVER';   // ゲームオーバー

// 再生タイミング定数 (秒)
const BASE_LIT  = 0.45;   // 点灯時間 (長くなるほど速くなるが最低0.22)
const BASE_GAP  = 0.20;   // 消灯時間（パッド間のスキマ）
const MIN_LIT   = 0.22;
const PAUSE_DUR = 0.70;   // ラウンド成功後の待機時間

class Game extends Scene {
  enter() {
    const p = P();
    this.high   = this.engine.storage.getHigh(meta.id);
    this.round  = 1;   // スコア = 完了したラウンド数
    this.seq    = [];  // ランダム配列（インデックス: 0-3）
    this.lit    = -1;  // 現在点灯中のパッドインデックス（-1=消灯）
    this.litTimer = 0; // 現在の点灯/消灯タイマー

    // プレイヤー入力フィードバック用（短く点灯させる）
    this.inputLit    = -1; // プレイヤータップで光るパッド
    this.inputTimer  = 0;

    this._startRound();
  }

  // ラウンド開始: シーケンスに1ステップ追加して再生開始
  _startRound() {
    this.seq.push(Math.floor(Math.random() * 4));
    this.state      = STATE_SHOW;
    this.showIdx    = 0;  // 次に再生するシーケンスインデックス
    this.litPhase   = 'off'; // 'on' | 'off' の2フェーズで制御
    this.litTimer   = BASE_GAP; // 最初に少し間を置いてから点灯
    this.lit        = -1;
    this.inputIdx   = 0;  // プレイヤーが次に入力すべきシーケンスインデックス
    this.status     = 'WATCH';
  }

  // 速度係数: ラウンドが進むほど速くなる（最低 MIN_LIT まで）
  _litDur() {
    const factor = Math.max(0.5, 1.0 - (this.seq.length - 1) * 0.03);
    return Math.max(MIN_LIT, BASE_LIT * factor);
  }

  update(dt) {
    // プレイヤータップのフィードバック点灯を消す
    if (this.inputTimer > 0) {
      this.inputTimer -= dt;
      if (this.inputTimer <= 0) this.inputLit = -1;
    }

    if (this.state === STATE_SHOW) {
      this.litTimer -= dt;
      if (this.litTimer <= 0) {
        if (this.litPhase === 'off') {
          // 消灯フェーズ終了 → 次のパッドを点灯
          if (this.showIdx >= this.seq.length) {
            // 全ステップ再生完了 → 入力フェーズへ
            this.state   = STATE_INPUT;
            this.status  = 'REPEAT';
            this.lit     = -1;
          } else {
            // 次パッドを点灯
            const padIdx = this.seq[this.showIdx];
            this.lit      = padIdx;
            this.litPhase = 'on';
            this.litTimer = this._litDur();
            this.engine.audio.beep(PADS[padIdx].freq, this._litDur() * 0.85, 'square', 0.3);
          }
        } else {
          // 点灯フェーズ終了 → 消灯してから次へ
          this.lit      = -1;
          this.litPhase = 'off';
          this.litTimer = BASE_GAP;
          this.showIdx++;
        }
      }
    } else if (this.state === STATE_PAUSE) {
      this.litTimer -= dt;
      if (this.litTimer <= 0) {
        this.round++;
        this._startRound();
      }
    }
  }

  onInput(action, data) {
    if (this.state === STATE_OVER) {
      if (action === 'back') return this.engine.toMenu();
      if (action === 'tap' || action === 'confirm') return this.enter();
      return;
    }
    if (action === 'back') return this.engine.toMenu();

    if (action === 'tap' && this.state === STATE_INPUT) {
      const i = hitPad(data.x, data.y);
      if (i < 0) return; // パッド外タップは無視

      // タップフィードバック: 短く点灯 + 音
      this.inputLit   = i;
      this.inputTimer = 0.18;
      this.engine.audio.beep(PADS[i].freq, 0.15, 'square', 0.3);

      if (i === this.seq[this.inputIdx]) {
        // 正解タップ
        this.inputIdx++;
        if (this.inputIdx >= this.seq.length) {
          // シーケンス全入力完了
          this.engine.audio.good();
          if (this.engine.storage.setHigh(meta.id, this.round)) this.high = this.round;
          this.state    = STATE_PAUSE;
          this.litTimer = PAUSE_DUR;
          this.status   = 'NICE!';
        }
      } else {
        // 不正解
        this.engine.audio.bad();
        // ハイスコア保存（round - 1 が完了ラウンド数）
        const score = this.round - 1;
        if (this.engine.storage.setHigh(meta.id, score)) this.high = score;
        this.state  = STATE_OVER;
        this.status = 'MISS!';
      }
    }
  }

  render(ctx) {
    const p = P();
    const e = this.engine;

    // ---- HUD ----
    e.text('BEEPER', W / 2, 14, 20, p.fg, 'center');
    e.text('ROUND ' + this.round, 54, 14, 15, p.mid, 'left'); // 左上BACKボタンを避ける
    e.text('HI ' + this.high, W - 14, 14, 15, p.dim, 'right');

    // ---- ステータスライン（HUD直下）----
    e.text(this.status, W / 2, 50, 16, p.warn, 'center');

    // ---- パッド描画 ----
    for (let i = 0; i < 4; i++) {
      const { x, y, w, h } = padRect(i);
      const isLit = (i === this.lit) || (i === this.inputLit);
      const dimKey    = PAD_DIM[i];
      const brightKey = PAD_BRIGHT[i];

      if (isLit) {
        // 点灯: 明るい塗り + 白枠
        e.rect(x, y, w, h, p[brightKey]);
        e.stroke(x, y, w, h, p.hi, 3);
      } else {
        // 消灯: 暗い塗り + dim枠
        e.rect(x, y, w, h, p.dark);
        e.stroke(x, y, w, h, p.dim, 2);
      }

      // パッド内アイコン（音符）
      const iconColor = isLit ? p.bg : p.dim;
      e.text('♪', x + w / 2, y + h / 2 - 14, 28, iconColor, 'center');
    }

    // ---- シーケンス長インジケーター ----
    // 現在のシーケンス長を小さいドットで表示
    const dotY = PAD_TOP + PAD_SIZE * 2 + PAD_GAP + 20;
    const dotR = 5;
    const dotSpacing = 14;
    const totalDots = this.seq.length;
    const startX = W / 2 - ((totalDots - 1) * dotSpacing) / 2;
    for (let d = 0; d < totalDots; d++) {
      const dx = startX + d * dotSpacing;
      // 入力フェーズでは入力済みドットを明るく
      let dotColor;
      if (this.state === STATE_INPUT && d < this.inputIdx) {
        dotColor = p.mid;
      } else {
        dotColor = p.dim;
      }
      ctx.fillStyle = dotColor;
      ctx.beginPath();
      ctx.arc(dx, dotY, dotR, 0, Math.PI * 2);
      ctx.fill();
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.state === STATE_OVER) {
      const score = this.round - 1;
      const oy = H / 2 - 80;
      e.rect(0, oy, W, 200, p.dark);
      e.stroke(0, oy, W, 200, p.bad, 3);
      e.text('GAME OVER', W / 2, oy + 18, 30, p.bad, 'center');
      e.text('SCORE: ' + score + ' ROUNDS', W / 2, oy + 66, 18, p.fg, 'center');
      e.text('HI: ' + this.high, W / 2, oy + 96, 16, p.dim, 'center');
      e.text('TAP TO RETRY', W / 2, oy + 138, 15, p.mid, 'center');
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/fire.js ----
(function(){
// FIRE : Game & Watch スタイルの救助ゲーム
// 燃える建物から飛び降りる人を担架で受け止め、右の救急車まで送り届ける。
// 担架の位置を左右に動かして飛び降り人を順番にバウンドさせるタイミングゲーム。

const meta = {
  id: 'fire',
  title: 'FIRE',
  desc: '落ちる人を担架で受け止め救助',
  glyph: 'A',
};

// --- レイアウト定数 ---
// バウンスポジション（担架が止まれるX座標）
// 救急車との重なりを避けるため間隔を広げた
const BOUNCE_XS = [85, 180, 268];         // 位置0,1,2 の中心X

const TRAMPOLINE_Y = 500;                 // 担架の上端Y（少し上に移動して視野確保）
const TRAMPOLINE_W = 72;                  // 担架の幅
const TRAMPOLINE_H = 14;                  // 担架の高さ
const GROUND_Y = 524;                     // 落下ミス判定ライン

// 建物（左端）
const BUILDING_X = 0;
const BUILDING_Y = 80;
const BUILDING_W = 62;
const BUILDING_H = 430;

// 救急車（右端）— バウンスポジション2(268)と重ならないよう右寄りに
const AMBULANCE_X = 300;
const AMBULANCE_Y = 470;
const AMBULANCE_W = 58;
const AMBULANCE_H = 58;

// 救急車の入口X（ジャンパーがここに向かって飛び込む）
const AMBULANCE_ENTRY_X = AMBULANCE_X + 4;

// ジャンパーが生成されるX（建物の右端付近）
const SPAWN_X = 44;
const SPAWN_Y = 210;   // 建物から飛び出す高さ

// ジャンパーサイズ
const JUMPER_W = 18;
const JUMPER_H = 22;

// 物理 — 重力を下げてゆっくり落下させる
const GRAVITY       = 480;    // px/s^2（元900→480に減速）
const BOUNCE_VY     = -520;   // バウンス時の初速（上向き・大きく飛ばす）
const BOUNCE_VX_BASE = 90;    // バウンス後の横速度（基本値）
const BOUNCE_VX_STEP = 25;    // bounceIdxごとの追加横速度
const SPAWN_VY_INIT  = -40;   // 建物から飛び出す初期縦速度（ほぼ水平気味に）

// 最終バウンス後（救急車へ）の速度
const FINAL_VX = 160;
const FINAL_VY = -380;

// 難易度スケーリング
const BASE_SPAWN_INTERVAL = 4.0;   // 最初の生成間隔（秒）
const MIN_SPAWN_INTERVAL  = 1.4;   // 最短生成間隔

// HUD
const HUD_Y = 10;

// バウンス数（0,1,2 の3段階を踏んで救助）
const BOUNCE_COUNT = 3;

class Game extends Scene {
  enter() {
    // --- 状態リセット ---
    this.score       = 0;
    this.lives       = 3;
    this.high        = this.engine.storage.getHigh(meta.id);
    this.dead        = false;
    this.tram        = 1;          // 担架の現在ポジション index (0/1/2)
    this.jumpers     = [];         // アクティブなジャンパー配列
    this.spawnTimer  = 2.0;        // 最初の生成まで少し待つ
    this.rescued     = 0;          // 今回救助した人数
    this.elapsed     = 0;          // 経過時間（難易度計算用）
    this.flameTick   = 0;          // 炎アニメ用タイマー
    this.shakeTimer  = 0;          // ダメージ時の画面揺れ
    this.flashTimer  = 0;          // 救助時のフラッシュ
    this.rescueFlash = 0;          // 救助成功表示タイマー
    this.lastRescueX = 0;          // 救助成功表示X座標
    this.lastRescueY = 0;          // 救助成功表示Y座標
  }

  // 現在の難易度による生成間隔
  _spawnInterval() {
    return Math.max(MIN_SPAWN_INTERVAL, BASE_SPAWN_INTERVAL - this.elapsed * 0.05);
  }

  // 新しいジャンパーを建物から生成
  _spawnJumper() {
    this.jumpers.push({
      x:          SPAWN_X,          // 現在のX
      y:          SPAWN_Y,          // 現在のY
      vx:         28,               // 右向きの初速（建物から飛び出す感じ）
      vy:         SPAWN_VY_INIT,    // ほぼ水平に飛び出す
      bounceIdx:  0,                // 次に向かうバウンスポジション index (0/1/2)
      state:      'falling',        // 'falling' | 'rescued' | 'dead'
      animTimer:  0,                // 救助/死亡アニメーション用タイマー
    });
  }

  update(dt) {
    // dead状態でもフレームを消費しないようにすぐリターン
    if (this.dead) return;

    this.elapsed    += dt;
    this.flameTick  += dt;
    if (this.shakeTimer  > 0) this.shakeTimer  -= dt;
    if (this.flashTimer  > 0) this.flashTimer  -= dt;
    if (this.rescueFlash > 0) this.rescueFlash -= dt;

    // 生成タイマー
    this.spawnTimer -= dt;
    if (this.spawnTimer <= 0) {
      this._spawnJumper();
      this.spawnTimer = this._spawnInterval();
    }

    // ジャンパー物理更新
    const toRemove = [];
    for (let i = 0; i < this.jumpers.length; i++) {
      const j = this.jumpers[i];

      // --- 終端状態のアニメーション消化 ---
      if (j.state === 'rescued') {
        j.animTimer += dt;
        if (j.animTimer > 0.8) toRemove.push(i);
        continue;
      }
      if (j.state === 'dead') {
        j.animTimer += dt;
        if (j.animTimer > 0.6) toRemove.push(i);
        continue;
      }

      // --- 重力・移動（NaN防止：isFiniteチェック） ---
      const dvx = isFinite(j.vx) ? j.vx : 0;
      const dvy = isFinite(j.vy) ? j.vy : 0;
      j.vy += GRAVITY * dt;
      j.x  += dvx * dt;
      j.y  += dvy * dt;

      // NaNが混入した場合の安全ネット
      if (!isFinite(j.x) || !isFinite(j.y)) {
        j.state = 'dead';
        j.animTimer = 0;
        continue;
      }

      const jCenterX = j.x + JUMPER_W / 2;
      const jBottom  = j.y + JUMPER_H;

      // --- 担架バウンス判定 ---
      // 下降中かつ担架の高さ帯に入ったとき判定
      if (j.vy > 0 && jBottom >= TRAMPOLINE_Y - 4 && jBottom <= GROUND_Y) {

        // bounceIdx が有効範囲内のときだけターゲットを参照
        if (j.bounceIdx >= 0 && j.bounceIdx < BOUNCE_COUNT) {
          const tramX    = BOUNCE_XS[this.tram];          // 担架の現在X
          const tramHalf = TRAMPOLINE_W / 2 + 10;         // 余裕幅

          // 担架にジャンパーが重なっているか？
          if (Math.abs(jCenterX - tramX) < tramHalf) {
            this._doBounce(j);
          }
        }
      }

      // --- 地面落下 = ミス ---
      if (jBottom > GROUND_Y + 10) {
        j.state = 'dead';
        j.animTimer = 0;
        this.lives--;
        this.shakeTimer = 0.4;
        this.engine.audio.bad();
        if (this.lives <= 0) {
          this._gameOver();
          return;  // ループを即中断（toRemoveが壊れないよう）
        }
      }

      // --- 画面外へ完全に消えた場合も削除 ---
      if (j.x > W + 80 || j.y > H + 80) {
        toRemove.push(i);
      }
    }

    // 重複排除 → 逆順で削除（indexズレ防止）
    const uniqueRemove = [...new Set(toRemove)].sort((a, b) => b - a);
    for (const idx of uniqueRemove) {
      this.jumpers.splice(idx, 1);
    }
  }

  // バウンス処理を切り出し（update肥大化防止）
  _doBounce(j) {
    const jCenterX = j.x + JUMPER_W / 2;

    if (j.bounceIdx < BOUNCE_COUNT - 1) {
      // --- 通常バウンス（まだ途中のポジション）---
      const vx = BOUNCE_VX_BASE + j.bounceIdx * BOUNCE_VX_STEP;
      j.vy = BOUNCE_VY;
      j.vx = vx;
      j.bounceIdx++;
      this.engine.audio.pick();
      this.score += 1;

    } else {
      // --- 最終バウンス（位置2→救急車へ飛び込む）---
      j.vy = FINAL_VY;
      j.vx = FINAL_VX;
      j.bounceIdx++;  // BOUNCE_COUNT(3) になる
      j.state = 'rescued';
      j.animTimer = 0;

      this.rescued++;
      this.score += 5;
      this.flashTimer  = 0.4;
      this.rescueFlash = 1.0;
      this.lastRescueX = j.x;
      this.lastRescueY = j.y;

      // sequence()は必ず配列を渡す（引数なしはThrowするため）
      this.engine.audio.sequence([
        { freq: 660, dur: 0.08 },
        { freq: 880, dur: 0.08 },
        { freq: 1100, dur: 0.10 },
      ]);
    }
  }

  _gameOver() {
    this.dead = true;
    // sequence()には必ず配列を渡す（引数なし → throws）
    this.engine.audio.sequence([
      { freq: 440, dur: 0.12 },
      { freq: 330, dur: 0.12 },
      { freq: 220, dur: 0.20 },
    ]);
    if (this.engine.storage.setHigh(meta.id, this.score)) this.high = this.score;
  }

  onInput(action, data) {
    if (this.dead) {
      if (action === 'tap' || action === 'confirm') {
        this.enter(); // リトライ
      } else if (action === 'back') {
        this.engine.toMenu();
      }
      return;
    }

    if (action === 'back') {
      this.engine.toMenu();
      return;
    }

    if (action === 'left') {
      if (this.tram > 0) {
        this.tram--;
        this.engine.audio.move();
      }
    } else if (action === 'right') {
      if (this.tram < BOUNCE_COUNT - 1) {
        this.tram++;
        this.engine.audio.move();
      }
    } else if (action === 'tap' && data) {
      // 画面の左半分タップ → 担架を左へ、右半分 → 右へ
      if (data.x < W / 2) {
        if (this.tram > 0) { this.tram--; this.engine.audio.move(); }
      } else {
        if (this.tram < BOUNCE_COUNT - 1) { this.tram++; this.engine.audio.move(); }
      }
    }
  }

  render(ctx) {
    const p = P();

    // 画面揺れエフェクト
    let shakeX = 0, shakeY = 0;
    if (this.shakeTimer > 0) {
      shakeX = (Math.random() - 0.5) * 8;
      shakeY = (Math.random() - 0.5) * 6;
    }
    if (shakeX !== 0 || shakeY !== 0) {
      ctx.save();
      ctx.translate(shakeX, shakeY);
    }

    // 救助フラッシュ（画面全体の淡い光）
    if (this.flashTimer > 0) {
      this.engine.rect(0, 0, W, H, p.hi + '18');
    }

    // === HUD ===
    // BACKボタン（x:6..48, y:8..44）を避けて x>=52 から描く
    this.engine.text('FIRE', 52, HUD_Y + 4, 18, p.warn, 'left');
    this.engine.text('SCORE ' + this.score, 52, HUD_Y + 26, 13, p.mid, 'left');
    this.engine.text('HI ' + this.high, W - 10, HUD_Y + 4, 13, p.dim, 'right');

    // ライフ表示（右上）— 'A'グリフで人を表現
    for (let i = 0; i < 3; i++) {
      const lx = W - 14 - i * 18;
      const ly = HUD_Y + 22;
      this.engine.text('A', lx, ly, 14, i < this.lives ? p.fg : p.dark, 'right');
    }

    // === 地面ライン ===
    this.engine.rect(0, GROUND_Y + 12, W, 4, p.dim);

    // === 建物（左） ===
    this._drawBuilding(p);

    // === 救急車（右） ===
    this._drawAmbulance(p);

    // === バウンスポジションマーカー（地面上の目印）===
    for (let i = 0; i < BOUNCE_COUNT; i++) {
      const bx = BOUNCE_XS[i];
      const isActive = (i === this.tram);
      // 担架が止まれる位置を示すマーカー（三角形風に矩形を重ねる）
      const mc = isActive ? p.fg : p.dim;
      this.engine.rect(bx - 6, GROUND_Y,     12, 4, mc);
      this.engine.rect(bx - 4, GROUND_Y + 4,  8, 4, mc);
      this.engine.rect(bx - 2, GROUND_Y + 8,  4, 4, mc);
      // ポジション番号（小さく）
      this.engine.text(String(i + 1), bx, GROUND_Y - 14, 11, mc, 'center');
    }

    // === 担架 ===
    this._drawTrampoline(p);

    // === ジャンパー ===
    for (const j of this.jumpers) {
      this._drawJumper(ctx, j, p);
    }

    // === 救助成功フィードバック（+5 表示）===
    if (this.rescueFlash > 0) {
      const alpha = Math.min(1, this.rescueFlash);
      const ry = AMBULANCE_Y - 10 - (1 - this.rescueFlash) * 30;
      ctx.globalAlpha = alpha;
      this.engine.text('+5 SAVED!', AMBULANCE_X + AMBULANCE_W / 2, ry, 16, p.hi, 'center');
      ctx.globalAlpha = 1.0;
    }

    // === 操作ガイド（下部）===
    if (!this.dead) {
      this.engine.text('← →  で担架を移動', W / 2, H - 26, 12, p.dim, 'center');
    }

    if (shakeX !== 0 || shakeY !== 0) {
      ctx.restore();
    }

    // === ゲームオーバーオーバーレイ ===
    if (this.dead) {
      // 半透明の暗い背景
      this.engine.rect(18, H / 2 - 110, W - 36, 220, p.dark);
      this.engine.stroke(18, H / 2 - 110, W - 36, 220, p.bad, 2);
      this.engine.text('GAME OVER', W / 2, H / 2 - 96, 28, p.bad,  'center');
      this.engine.text('SCORE   ' + this.score,   W / 2, H / 2 - 54, 20, p.fg,   'center');
      this.engine.text('RESCUED  ' + this.rescued, W / 2, H / 2 - 24, 16, p.mid,  'center');
      this.engine.text('BEST    ' + this.high,    W / 2, H / 2 +  6, 16, p.dim,  'center');
      // 区切り線
      this.engine.rect(W / 2 - 70, H / 2 + 30, 140, 2, p.dim);
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 42, 15, p.fg,   'center');
      this.engine.text('‹ BACK',       W / 2, H / 2 + 66, 13, p.dim,  'center');
    }
  }

  // 建物描画（炎アニメつき）
  _drawBuilding(p) {
    // 建物本体
    this.engine.rect(BUILDING_X, BUILDING_Y, BUILDING_W, BUILDING_H, p.dark);
    this.engine.stroke(BUILDING_X, BUILDING_Y, BUILDING_W, BUILDING_H, p.dim, 2);

    // 窓グリッド（装飾）
    for (let row = 0; row < 5; row++) {
      for (let col = 0; col < 2; col++) {
        const wx = BUILDING_X + 8 + col * 24;
        const wy = BUILDING_Y + 20 + row * 60;
        // 上の2階の窓は炎で赤くなっている
        const wColor = (row <= 1) ? p.warn : p.mid;
        this.engine.rect(wx, wy, 14, 14, p.bg);
        this.engine.stroke(wx, wy, 14, 14, wColor, 1);
      }
    }

    // 建物上部の炎（アニメ）— 2フレーム交互
    const flameToggle = (Math.floor(this.flameTick * 4) % 2 === 0);
    const fc1 = flameToggle ? p.warn : p.bad;
    const fc2 = flameToggle ? p.bad  : p.warn;

    this.engine.rect(BUILDING_X + 2,  BUILDING_Y - 26, 12, 30, fc1);
    this.engine.rect(BUILDING_X + 16, BUILDING_Y - 20, 10, 24, fc2);
    this.engine.rect(BUILDING_X + 28, BUILDING_Y - 30, 14, 34, fc1);
    this.engine.rect(BUILDING_X + 46, BUILDING_Y - 18, 10, 22, fc2);

    // 建物の出口プラットフォーム（ジャンパーが飛び出す場所）
    this.engine.rect(BUILDING_X + BUILDING_W - 4, SPAWN_Y - 8, 14, 6, p.fg);

    // 「FIRE」ラベル（建物内）
    this.engine.text('FIRE', BUILDING_X + BUILDING_W / 2, BUILDING_Y + BUILDING_H / 2, 12, p.bad, 'center');
  }

  // 救急車描画
  _drawAmbulance(p) {
    // 車体
    this.engine.rect(AMBULANCE_X, AMBULANCE_Y, AMBULANCE_W, AMBULANCE_H, p.dark);
    this.engine.stroke(AMBULANCE_X, AMBULANCE_Y, AMBULANCE_W, AMBULANCE_H, p.fg, 2);

    // 赤十字マーク
    const cx = AMBULANCE_X + AMBULANCE_W / 2;
    const cy = AMBULANCE_Y + AMBULANCE_H / 2 - 6;
    this.engine.rect(cx - 9, cy - 3, 18, 6, p.bad);
    this.engine.rect(cx - 3, cy - 9, 6, 18, p.bad);

    // 「SAVE」ラベル
    this.engine.text('SAVE', cx, AMBULANCE_Y + AMBULANCE_H - 16, 11, p.fg, 'center');

    // タイヤ
    this.engine.rect(AMBULANCE_X + 4,              AMBULANCE_Y + AMBULANCE_H - 2, 14, 8, p.mid);
    this.engine.rect(AMBULANCE_X + AMBULANCE_W - 18, AMBULANCE_Y + AMBULANCE_H - 2, 14, 8, p.mid);

    // ライトアニメ（点滅）
    const lightOn = (Math.floor(this.flameTick * 3) % 2 === 0);
    if (lightOn) {
      this.engine.rect(AMBULANCE_X + 3, AMBULANCE_Y + 3, 9, 7, p.warn);
    }

    // 入口（左側に開口部を示す線）
    this.engine.rect(AMBULANCE_X, AMBULANCE_Y + 10, 4, AMBULANCE_H - 24, p.bg);
  }

  // 担架描画
  _drawTrampoline(p) {
    const tx = BOUNCE_XS[this.tram] - TRAMPOLINE_W / 2;
    const ty = TRAMPOLINE_Y;

    // 担架を運ぶ救助員（左右）
    this._drawRescuer(tx - 10,              ty - 28, p);
    this._drawRescuer(tx + TRAMPOLINE_W - 4, ty - 28, p);

    // 担架本体（明るい色で目立たせる）
    this.engine.rect(tx, ty, TRAMPOLINE_W, TRAMPOLINE_H, p.fg);
    this.engine.stroke(tx, ty, TRAMPOLINE_W, TRAMPOLINE_H, p.hi, 2);

    // 担架中央のクロス模様
    this.engine.rect(tx + TRAMPOLINE_W / 2 - 1, ty + 2, 2, TRAMPOLINE_H - 4, p.bg);
    this.engine.rect(tx + 2, ty + TRAMPOLINE_H / 2 - 1, TRAMPOLINE_W - 4, 2, p.bg);
  }

  // 救助員の簡易人型
  _drawRescuer(x, y, p) {
    this.engine.rect(x + 2, y,      8, 8,  p.fg);   // 頭
    this.engine.rect(x + 3, y + 8,  6, 12, p.mid);  // 胴体
    this.engine.rect(x + 2, y + 20, 4, 8,  p.fg);   // 左脚
    this.engine.rect(x + 6, y + 20, 4, 8,  p.fg);   // 右脚
  }

  // ジャンパー（飛び降り人）描画
  _drawJumper(ctx, j, p) {
    // 座標を整数に丸める（NaN対策を兼ねる）
    const x = isFinite(j.x) ? Math.round(j.x) : -100;
    const y = isFinite(j.y) ? Math.round(j.y) : -100;

    if (j.state === 'rescued') {
      // 救助済み：右へ飛び込みながらフェードアウト
      const alpha = Math.max(0, 1 - j.animTimer / 0.8);
      ctx.globalAlpha = alpha;
      this.engine.rect(x, y, JUMPER_W, JUMPER_H, p.hi);
      this.engine.text('★', x + JUMPER_W / 2, y - 6, 14, p.warn, 'center');
      ctx.globalAlpha = 1.0;
      return;
    }

    if (j.state === 'dead') {
      // 落下ミス：X印でフェードアウト
      const alpha = Math.max(0, 1 - j.animTimer / 0.6);
      ctx.globalAlpha = alpha;
      this.engine.text('X', x + JUMPER_W / 2, y, 22, p.bad, 'center');
      ctx.globalAlpha = 1.0;
      return;
    }

    // 通常（落下/バウンス中）：人型
    this.engine.rect(x + 4, y,      10, 9,  p.fg);   // 頭
    this.engine.rect(x + 5, y + 9,   8, 9,  p.mid);  // 胴体
    this.engine.rect(x,     y + 6,   5, 4,  p.fg);   // 左腕
    this.engine.rect(x + 13, y + 6,  5, 4,  p.fg);   // 右腕
    this.engine.rect(x + 4, y + 18,  4, 4,  p.fg);   // 左脚
    this.engine.rect(x + 10, y + 18, 4, 4,  p.fg);   // 右脚

    // 次のターゲットポジションへの目印（担架が止まるべき場所を細線で示す）
    if (j.bounceIdx >= 0 && j.bounceIdx < BOUNCE_COUNT) {
      const targetX = BOUNCE_XS[j.bounceIdx];
      // ターゲットとジャンパーが横に近いほど明るく表示
      const dist = Math.abs((j.x + JUMPER_W / 2) - targetX);
      const showGuide = dist < 80;
      if (showGuide) {
        this.engine.rect(targetX - 1, TRAMPOLINE_Y - 18, 2, 16, p.dim);
      }
    }
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/meteor.js ----
(function(){
// METEOR : ゆっくり迫る隕石をミサイルで迎撃するストラテジー防衛ゲーム。
// ステージ制：序盤は1個ずつ読んで破壊、徐々に密度が上がりステージ末にボス隕石登場。
// 全都市が破壊されたらゲームオーバー。

const meta = {
  id: 'meteor',
  title: 'METEOR',
  desc: '降る隕石を迎撃して街を守れ',
  glyph: '*',
};

// ---- 定数 ----
const CITY_COUNT   = 5;
const CITY_W       = 28;
const CITY_H       = 18;
const GROUND_Y     = H - 40;
const BATTERY_X    = W / 2;
const BATTERY_Y    = GROUND_Y - 4;

// ミサイル（遅め＝狙いを要求する）
const MISSILE_SPD   = 110;   // px/s
const BASE_MAX_MISSILES = 2; // 初期同時ミサイル数
const FIRE_COOLDOWN = 0.55;  // 発射間隔（秒）

// 爆発 — grow then FADE OUT (alpha, no shrink)
const BLAST_GROW     = 38;   // 通常爆発最大半径
const BLAST_GROW_BIG = 115;  // ビッグ爆発最大半径
const BLAST_GROW_RATE = 50;  // 拡大速度 px/s（遅め）
const BLAST_FADE_SEC  = 1.2; // フェードアウト時間（秒）— 合計アニメを長く

// ビッグブラスト残弾
const BIG_CHARGES_MAX  = 3;
const BIG_RECHARGE_SEC = 14;

// 通常ブラストダメージ（パワーアップで増加）
const BLAST_DAMAGE_NORMAL_BASE = 1;
const BLAST_DAMAGE_BIG         = 3; // ビッグは常に3

// ---- 隕石速度 ----
const METEOR_SPD_MIN       = 2;
const METEOR_SPD_MAX       = 5;
const METEOR_SPD_MAX_LATE  = 7;

const FAST_CHANCE  = 0.10;
const FAST_SPD_MIN = 14;
const FAST_SPD_MAX = 24;

// 隕石サイズ
const METEOR_R_MIN   = 7;
const METEOR_R_MAX   = 34;
const GIANT_R_THRESH = 22;
const SMALL_R_THRESH = 10;
const LARGE_R_THRESH = 16;

// ボス隕石 — 大型化！画面の半分近くを覆う威圧感
const BOSS_R_MIN    = 95;    // 旧48から大幅増
const BOSS_R_MAX    = 125;   // 旧70から大幅増（最大でW=360の1/3を超える）
const BOSS_SPD_MIN  = 1.0;   // 大きい分ゆっくり
const BOSS_SPD_MAX  = 1.8;
const BOSS_HP_BASE  = 24;    // 旧10から大幅増
const BOSS_HP_PER_STAGE = 5; // ステージ毎に+5（旧+2）

// スコア
const METEOR_SCORE_BASE = 10;
const BOSS_SCORE_BASE   = 250;

// ---- ステージタイプ（ステージ2以降でサイクル） ----
// STAGE_TYPES[i % STAGE_TYPES.length] で決定
const STAGE_TYPES = [
  'NORMAL', // 未使用（ステージ1固定）
  'FAST',   // 全速度上昇
  'SWARM',  // 密集スポーン
  'TINY',   // 小型多数
  'GIANT',  // 大型高HP
  'CHAOS',  // 速度＋密度＋混合
];

// ---- アイテム隕石のパワーアップ種別 ----
// 'MULTI'  : 同時ミサイル数+1（上限5）
// 'POWER'  : 通常爆発ダメージ+1（上限3）
// 'WIDE'   : 通常爆発半径+12（上限+36）
// 'SCATTER': 爆発時に小さな破片ブラストを撒く
const ITEM_TYPES = ['MULTI', 'POWER', 'WIDE', 'SCATTER'];

// ---- HP計算（半径に基づく） ----
function calcMeteorHP(r) {
  if (r < SMALL_R_THRESH)  return 1;
  if (r < LARGE_R_THRESH)  return 2;
  if (r < GIANT_R_THRESH)  return 3;
  return 4;
}

// ---- ステージ定義 ----
function makeStageScript(stage, stageType) {
  const events = [];
  // ステージタイプに応じてパラメータを調整
  let baseDelay  = Math.max(3.5 - stage * 0.25, 1.1);
  let bossT      = 72 + stage * 4;
  let itemChance = Math.min(0.08 + stage * 0.025, 0.22); // アイテム隕石出現確率

  // タイプ別にbossT/baseDelayを調整
  if (stageType === 'SWARM') { baseDelay *= 0.5; bossT = 55 + stage * 3; }
  if (stageType === 'FAST')  { bossT = 60 + stage * 3; }
  if (stageType === 'CHAOS') { baseDelay *= 0.65; bossT = 58 + stage * 3; }

  let t = 0;
  // 序盤
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 2.0;
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 1.8;

  // 中盤
  const midGiant = (stageType === 'GIANT');
  const midTiny  = (stageType === 'TINY');
  events.push({ t, type: 'meteor', count: 1, forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.5;

  let waveMax = 2;
  if (stageType === 'SWARM') waveMax = 5;
  else if (stageType === 'CHAOS') waveMax = 4;
  else waveMax = Math.min(1 + Math.floor(stage / 2), 3);

  events.push({ t, type: 'meteor', count: waveMax, forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.4;
  events.push({ t, type: 'meteor', count: 1, forceSize: null, itemChance });
  t += baseDelay * 1.3;
  events.push({ t, type: 'meteor', count: Math.min(1 + Math.floor(stage / 1.5), 4), forceSize: midGiant ? 'giant' : (midTiny ? 'tiny' : null), itemChance });
  t += baseDelay * 1.2;

  // 後半
  let numLate = Math.min(2 + stage, 6);
  if (stageType === 'SWARM') numLate = Math.min(numLate + 3, 9);
  if (stageType === 'CHAOS') numLate = Math.min(numLate + 2, 7);

  while (t < bossT - 10) {
    const cnt = Math.min(1 + Math.floor(Math.random() * numLate), numLate);
    const giant = (stageType === 'GIANT') || (stageType === 'CHAOS' && Math.random() < 0.3) || Math.random() < 0.15;
    const tiny  = (stageType === 'TINY') || (Math.random() < 0.05);
    events.push({
      t, type: 'meteor', count: cnt,
      forceSize: giant ? 'giant' : (tiny ? 'tiny' : null),
      itemChance,
    });
    const minGap = stageType === 'SWARM' ? 0.5 : 0.9;
    t += Math.max(baseDelay * (0.85 - stage * 0.04), minGap);
  }

  // ボス登場
  events.push({ t: bossT, type: 'boss' });
  return events;
}

// ---- 岩石ポリゴン頂点の生成 ----
function makeRockVerts(r, seed) {
  const count = 8 + Math.floor((seed % 4));  // 8〜11頂点
  const verts = [];
  for (let i = 0; i < count; i++) {
    const baseAngle = (i / count) * Math.PI * 2;
    const s1 = Math.sin(seed * 31.7 + i * 12.3);
    const s2 = Math.sin(seed * 17.1 + i * 7.9);
    const angleJitter = (s1 * 0.5) / count;
    const angle = baseAngle + angleJitter;
    const rFrac = 0.60 + 0.50 * ((s2 + 1) / 2);
    verts.push({ dx: Math.cos(angle) * r * rFrac, dy: Math.sin(angle) * r * rFrac });
  }
  return verts;
}

// ---- ユニークID ----
let _nextBlastId  = 1;
let _nextMeteorSeed = 1;

// ---- ヘルパー ----
function clamp(v, lo, hi) { return v < lo ? lo : v > hi ? hi : v; }

// ステージタイプの速度倍率
function stageSpeedMult(stageType) {
  if (stageType === 'FAST')  return 2.8;
  if (stageType === 'SWARM') return 1.4;
  if (stageType === 'TINY')  return 2.2;
  if (stageType === 'CHAOS') return 2.0;
  return 1.0;
}

class Game extends Scene {
  enter() {
    this.score      = 0;
    this.high       = this.engine.storage.getHigh(meta.id);
    this.dead       = false;

    this._elapsed   = 0;

    // ステージ
    this._stage     = 0;
    this._stageType = 'NORMAL';
    this._stageScript = makeStageScript(this._stage, this._stageType);
    this._scriptIdx   = 0;
    this._bossPending = false;
    this._bossAlive   = false;
    this._bossIdx     = -1;
    this._stageClearing = false;
    this._stageClearTimer = 0;

    this.cities     = Array(CITY_COUNT).fill(true);
    this.meteors    = [];
    this.missiles   = [];
    this.blasts     = [];
    this.cityBlasts = [];

    this._fireCooldown = 0;

    this._bigCharges  = BIG_CHARGES_MAX;
    this._bigRecharge = 0;
    this._bigArmed    = false;

    // パワーアップ状態
    this._powerups = {
      missileMax:    BASE_MAX_MISSILES, // MULTI
      blastDamage:   BLAST_DAMAGE_NORMAL_BASE, // POWER
      blastRadiusAdd: 0,  // WIDE（ピクセル加算）
      scatter:       false, // SCATTER
    };
  }

  _bigBtnRect() { return { x: W / 2 - 48, y: 44, w: 112, h: 28 }; }

  _calcNormalSpd() {
    const frac   = clamp(this._stage / 6, 0, 1);
    const spdMax = METEOR_SPD_MAX + (METEOR_SPD_MAX_LATE - METEOR_SPD_MAX) * frac;
    const base   = METEOR_SPD_MIN + Math.random() * (spdMax - METEOR_SPD_MIN);
    return base * stageSpeedMult(this._stageType);
  }

  _calcFastSpd() {
    const base = FAST_SPD_MIN + Math.random() * (FAST_SPD_MAX - FAST_SPD_MIN);
    return base * clamp(stageSpeedMult(this._stageType) * 0.7, 1, 3);
  }

  // ---- onInput ----
  onInput(action, data) {
    if (this._stageClearing) return;
    if (this.dead) {
      if (action === 'back') { this.engine.toMenu(); return; }
      if (action === 'tap' || action === 'confirm') { this.enter(); return; }
      return;
    }
    if (action === 'back') { this.engine.toMenu(); return; }

    if (action === 'tap' && data) {
      const b = this._bigBtnRect();
      if (data.x >= b.x && data.x <= b.x + b.w && data.y >= b.y && data.y <= b.y + b.h) {
        this._bigArmed = this._bigArmed ? false : (this._bigCharges > 0);
        this.engine.audio.select();
        return;
      }
      const big = this._bigArmed;
      this._fireMissile(data.x, data.y, big);
      if (big) this._bigArmed = false;
    }
    if (action === 'confirm') {
      this._bigArmed = this._bigArmed ? false : (this._bigCharges > 0);
    }
  }

  // ---- 発射（クールダウン＋上限チェック） ----
  _fireMissile(tx, ty, big) {
    if (ty >= GROUND_Y) return;
    if (this._fireCooldown > 0) return;
    const activeCount = this.missiles.filter(m => !m.done).length;
    if (activeCount >= this._powerups.missileMax) return;

    if (big) {
      if (this._bigCharges <= 0) return;
      this._bigCharges--;
    }

    const dx = tx - BATTERY_X;
    const dy = ty - BATTERY_Y;
    const dist = Math.hypot(dx, dy);
    if (dist < 1) return;

    this.missiles.push({
      x: BATTERY_X, y: BATTERY_Y,
      tx, ty,
      vx: (dx / dist) * MISSILE_SPD,
      vy: (dy / dist) * MISSILE_SPD,
      done: false,
      big: !!big,
    });
    this._fireCooldown = FIRE_COOLDOWN;
    this.engine.audio.move();
  }

  // ---- update ----
  update(dt) {
    if (this.dead) return;

    if (this._fireCooldown > 0) {
      this._fireCooldown = Math.max(0, this._fireCooldown - dt);
    }

    // ステージクリア演出
    if (this._stageClearing) {
      this._stageClearTimer -= dt;
      if (this._stageClearTimer <= 0) {
        this._stage++;
        this._elapsed = 0;
        // ステージ2以降でタイプ決定（1-indexed で0はNORMAL）
        if (this._stage === 0) {
          this._stageType = 'NORMAL';
        } else {
          const types = STAGE_TYPES.filter(t => t !== 'NORMAL');
          this._stageType = types[(this._stage - 1) % types.length];
        }
        this._stageScript = makeStageScript(this._stage, this._stageType);
        this._scriptIdx = 0;
        this._bossPending = false;
        this._bossAlive = false;
        this._bossIdx = -1;
        this._stageClearing = false;
        this.meteors = [];
        this.missiles = [];
        this.blasts = [];
      }
      return;
    }

    this._elapsed += dt;

    // ビッグブラスト補充
    if (this._bigCharges < BIG_CHARGES_MAX) {
      this._bigRecharge += dt;
      if (this._bigRecharge >= BIG_RECHARGE_SEC) {
        this._bigRecharge -= BIG_RECHARGE_SEC;
        this._bigCharges++;
      }
    } else {
      this._bigRecharge = 0;
    }

    // ---- スクリプト式スポーン ----
    if (!this._bossAlive) {
      while (
        this._scriptIdx < this._stageScript.length &&
        this._stageScript[this._scriptIdx].t <= this._elapsed
      ) {
        const ev = this._stageScript[this._scriptIdx];
        this._scriptIdx++;
        if (ev.type === 'boss') {
          this._spawnBoss();
        } else if (ev.type === 'meteor') {
          const cnt = ev.count || 1;
          for (let c = 0; c < cnt; c++) {
            this._spawnMeteor(ev.forceSize, ev.itemChance || 0);
          }
        }
      }
    }

    // 隕石移動
    for (let i = this.meteors.length - 1; i >= 0; i--) {
      const m = this.meteors[i];
      if (!m || m.x == null) { this.meteors.splice(i, 1); continue; }
      const dx = m.tx - m.x;
      const dy = m.ty - m.y;
      const dist = Math.hypot(dx, dy);

      if (dist < m.spd * dt + 1) {
        // 地面到達
        if (m.boss) {
          this._impactCity(m.tx, m.ty);
          this._impactCity(m.tx, m.ty);
          this._bossAlive = false;
          this._bossIdx = -1;
        } else if (m.isItem) {
          // アイテム隕石が地面に落下しても何も得られない
        } else {
          this._impactCity(m.tx, m.ty);
        }
        this.meteors.splice(i, 1);
        if (this._bossIdx === i) { this._bossAlive = false; this._bossIdx = -1; }
        else if (this._bossIdx > i) this._bossIdx--;
        continue;
      }
      const ratio = m.spd / dist;
      m.x += dx * ratio * dt;
      m.y += dy * ratio * dt;

      // 軌跡
      const trailMax = m.fast ? 8 : (m.boss ? 4 : 5);
      m.trail.push({ x: m.x, y: m.y });
      if (m.trail.length > trailMax) m.trail.shift();

      m.rot += (m.fast ? 0.8 : (m.boss ? 0.12 : 0.4)) * dt;
    }

    // ミサイル移動
    for (let i = this.missiles.length - 1; i >= 0; i--) {
      const ms = this.missiles[i];
      if (!ms) { this.missiles.splice(i, 1); continue; }
      if (ms.done) { this.missiles.splice(i, 1); continue; }
      ms.x += ms.vx * dt;
      ms.y += ms.vy * dt;
      const ddx = ms.tx - ms.x;
      const ddy = ms.ty - ms.y;
      if (Math.hypot(ddx, ddy) < MISSILE_SPD * dt * 1.5 + 4) {
        this._spawnBlast(ms.tx, ms.ty, ms.big);
        ms.done = true;
      }
    }

    // 爆発更新 — grow then FADE (alpha decreases, radius stays at maxR)
    for (let i = this.blasts.length - 1; i >= 0; i--) {
      const b = this.blasts[i];
      if (!b) { this.blasts.splice(i, 1); continue; }

      if (b.growing) {
        b.r += BLAST_GROW_RATE * dt;
        if (b.r >= b.maxR) {
          b.r = b.maxR;
          b.growing = false;
          b.fadeTimer = BLAST_FADE_SEC; // フェード開始
        }
      } else {
        // フェードアウト（半径は変えない or わずかに拡大して壮大に見せる）
        b.fadeTimer -= dt;
        b.r = Math.min(b.maxR * 1.05, b.r + 4 * dt); // わずかに膨らむ
        if (b.fadeTimer <= 0) {
          this.blasts.splice(i, 1);
          continue;
        }
      }

      // 爆発ヒット判定（成長中＋フェード中も有効）
      for (let j = this.meteors.length - 1; j >= 0; j--) {
        const m = this.meteors[j];
        if (!m) continue;
        if (Math.hypot(m.x - b.x, m.y - b.y) > b.r + m.r) continue;
        if (m.hitBlastIds.has(b.id)) continue;
        m.hitBlastIds.add(b.id);

        if (m.isItem) {
          // アイテム隕石を撃ち落とした！
          this._collectItem(m);
          if (this._bossIdx > j) this._bossIdx--;
          this.meteors.splice(j, 1);
          continue;
        }

        m.hp -= b.damage;
        if (m.hp <= 0) {
          if (m.boss) {
            this.score += BOSS_SCORE_BASE * (this._stage + 1);
            this._bossAlive = false;
            this._bossIdx = -1;
            this._stageClearing = true;
            this._stageClearTimer = 2.2;
            this.engine.audio.sequence([
              { freq: 440, dur: 0.08, type: 'square', vol: 0.15 },
              { freq: 660, dur: 0.08, type: 'square', vol: 0.15 },
              { freq: 880, dur: 0.10, type: 'square', vol: 0.18 },
              { freq: 1320, dur: 0.16, type: 'square', vol: 0.18 },
            ]);
          } else {
            const sizeBonus = Math.ceil(m.maxHp);
            this.score += METEOR_SCORE_BASE * sizeBonus;
            this.engine.audio.good();
          }
          if (this._bossIdx > j) this._bossIdx--;
          this.meteors.splice(j, 1);
        }
      }
    }

    // 都市爆発エフェクト更新
    for (let i = this.cityBlasts.length - 1; i >= 0; i--) {
      const cb = this.cityBlasts[i];
      if (!cb) { this.cityBlasts.splice(i, 1); continue; }
      cb.t -= dt;
      cb.r += 60 * dt;
      if (cb.t <= 0) this.cityBlasts.splice(i, 1);
    }

    // ゲームオーバー判定
    if (this.cities.every(c => !c)) {
      this.dead = true;
      this.engine.audio.bad();
      if (this.engine.storage.setHigh(meta.id, this.score)) this.high = this.score;
    }
  }

  // ---- 通常隕石スポーン ----
  // forceSize: null | 'giant' | 'tiny'
  _spawnMeteor(forceSize, itemChance) {
    const x = 18 + Math.random() * (W - 36);
    const alive = this.cities.map((c, i) => c ? i : -1).filter(i => i >= 0);
    let tx;
    if (alive.length > 0 && Math.random() < 0.7) {
      const idx = alive[Math.floor(Math.random() * alive.length)];
      tx = CITY_XS[idx] + CITY_W / 2 + (Math.random() * 24 - 12);
    } else {
      tx = 18 + Math.random() * (W - 36);
    }
    const ty = GROUND_Y;

    // アイテム隕石判定（ステージ1は出ない）
    const spawnItem = this._stage >= 1 && Math.random() < (itemChance || 0);

    let r;
    if (forceSize === 'tiny') {
      r = METEOR_R_MIN + Math.random() * (SMALL_R_THRESH - METEOR_R_MIN + 2);
    } else if (forceSize === 'giant') {
      r = GIANT_R_THRESH + Math.random() * (METEOR_R_MAX - GIANT_R_THRESH);
    } else if (Math.random() < 0.12) {
      r = GIANT_R_THRESH + Math.random() * (METEOR_R_MAX - GIANT_R_THRESH);
    } else {
      r = Math.max(METEOR_R_MIN,
        METEOR_R_MIN + Math.random() * Math.random() * (GIANT_R_THRESH - METEOR_R_MIN)
      );
    }

    // アイテム隕石は固定サイズ（中くらい）
    if (spawnItem) r = 14 + Math.random() * 6;

    const isFast = !spawnItem && Math.random() < FAST_CHANCE;
    const spd = isFast ? this._calcFastSpd() : this._calcNormalSpd();
    const maxHp = spawnItem ? 1 : calcMeteorHP(r);
    const seed = _nextMeteorSeed++;
    const itemType = spawnItem ? ITEM_TYPES[Math.floor(Math.random() * ITEM_TYPES.length)] : null;

    this.meteors.push({
      x, y: -METEOR_R_MAX - 4,
      tx, ty, spd, r,
      hp: maxHp, maxHp,
      fast: isFast,
      boss: false,
      isItem: spawnItem,
      itemType,
      trail: [],
      rot: Math.random() * Math.PI * 2,
      verts: makeRockVerts(r, seed),
      seed,
      hitBlastIds: new Set(),
    });
  }

  // ---- ボス隕石スポーン ----
  _spawnBoss() {
    const r = BOSS_R_MIN + Math.random() * (BOSS_R_MAX - BOSS_R_MIN);
    // 半径が大きいため、画面内に収めるようにx範囲を制限
    const margin = r + 8;
    const xMin = clamp(margin, 20, W - 20);
    const xMax = clamp(W - margin, 20, W - 20);
    const x  = xMin + Math.random() * Math.max(0, xMax - xMin);
    const tx = xMin + Math.random() * Math.max(0, xMax - xMin);
    const ty = GROUND_Y;
    const spd = BOSS_SPD_MIN + Math.random() * (BOSS_SPD_MAX - BOSS_SPD_MIN);
    const maxHp = BOSS_HP_BASE + this._stage * BOSS_HP_PER_STAGE;
    const seed = _nextMeteorSeed++;

    const bossEntry = {
      x, y: -r - 4,
      tx, ty, spd, r,
      hp: maxHp, maxHp,
      fast: false,
      boss: true,
      isItem: false,
      itemType: null,
      trail: [],
      rot: Math.random() * Math.PI * 2,
      verts: makeRockVerts(r, seed),
      seed,
      hitBlastIds: new Set(),
    };
    this.meteors.push(bossEntry);
    this._bossIdx = this.meteors.length - 1;
    this._bossAlive = true;

    // ボス登場効果音
    this.engine.audio.sequence([
      { freq: 200, dur: 0.14, type: 'sawtooth', vol: 0.18 },
      { freq: 160, dur: 0.18, type: 'sawtooth', vol: 0.18 },
      { freq: 120, dur: 0.22, type: 'sawtooth', vol: 0.18 },
    ]);
  }

  // ---- アイテム取得 ----
  _collectItem(m) {
    const type = m.itemType;
    const pu = this._powerups;

    if (type === 'MULTI') {
      pu.missileMax = Math.min(pu.missileMax + 1, 5);
    } else if (type === 'POWER') {
      pu.blastDamage = Math.min(pu.blastDamage + 1, 3);
    } else if (type === 'WIDE') {
      pu.blastRadiusAdd = Math.min(pu.blastRadiusAdd + 12, 36);
    } else if (type === 'SCATTER') {
      pu.scatter = true;
    }

    // 取得音
    this.engine.audio.sequence([
      { freq: 880, dur: 0.06, type: 'square', vol: 0.16 },
      { freq: 1320, dur: 0.08, type: 'square', vol: 0.18 },
      { freq: 1760, dur: 0.10, type: 'square', vol: 0.20 },
    ]);
  }

  // ---- 爆発スポーン ----
  _spawnBlast(x, y, big, isScatter) {
    const baseR   = big ? BLAST_GROW_BIG : (BLAST_GROW + this._powerups.blastRadiusAdd);
    const maxR    = Math.max(6, baseR);
    const dmg     = big ? BLAST_DAMAGE_BIG : this._powerups.blastDamage;
    const id      = _nextBlastId++;
    this.blasts.push({
      x, y,
      r: 4,
      maxR,
      growing: true,
      fadeTimer: BLAST_FADE_SEC,
      big: !!big,
      id,
      damage: dmg,
      isScatter: !!isScatter,
    });
    if (!isScatter) {
      this.engine.audio.pick();
      if (big) {
        this.engine.audio.sequence([
          { freq: 330, dur: 0.06, type: 'square', vol: 0.18 },
          { freq: 220, dur: 0.12, type: 'sawtooth', vol: 0.16 },
        ]);
      }
      // SCATTERパワーアップ：通常爆発の周囲に小型爆発を6つ散布
      if (!big && this._powerups.scatter) {
        const count = 6;
        for (let i = 0; i < count; i++) {
          const angle = (i / count) * Math.PI * 2;
          const dist  = 28 + Math.random() * 18;
          const sx = x + Math.cos(angle) * dist;
          const sy = y + Math.sin(angle) * dist;
          // 画面外に出ないようにクランプ
          if (sy > GROUND_Y - 4) continue;
          this._spawnBlast(sx, sy, false, true);
        }
      }
    }
  }

  // ---- 都市ダメージ ----
  _impactCity(ix, iy) {
    let bestDist = Infinity, bestIdx = -1;
    for (let i = 0; i < CITY_COUNT; i++) {
      if (!this.cities[i]) continue;
      const cx = CITY_XS[i] + CITY_W / 2;
      const d = Math.abs(cx - ix);
      if (d < bestDist) { bestDist = d; bestIdx = i; }
    }
    if (bestIdx >= 0 && bestDist < CITY_W * 2.5) {
      this.cities[bestIdx] = false;
      this.engine.audio.bad();
      this.cityBlasts.push({
        x: CITY_XS[bestIdx] + CITY_W / 2,
        y: GROUND_Y - CITY_H / 2,
        r: 8, t: 0.7,
      });
    }
  }

  // ---- render ----
  render(ctx) {
    const p = P();

    // ---- HUD（x>=52 でBACKボタンを避ける） ----
    const stageLabel = 'ST' + (this._stage + 1);
    this.engine.text(stageLabel, 52, 8, 14, p.mid, 'left');

    // ステージタイプラベル（ステージ2以降）
    if (this._stage >= 1 && this._stageType !== 'NORMAL') {
      this.engine.text(this._stageType, 52, 24, 11, p.warn, 'left');
    }

    this.engine.text('SCORE ' + this.score, W - 12, 8, 14, p.fg, 'right');
    this.engine.text('BEST  ' + this.high,  W - 12, 26, 11, p.dim, 'right');
    const aliveCount = this.cities.filter(Boolean).length;
    this.engine.text('CITY ' + aliveCount, 52, 38, 11, p.warn, 'left');

    // パワーアップHUD（コンパクト表示）
    this._drawPowerupHUD(ctx, p);

    // ビッグブラスト HUD
    this._drawBigChargeHUD(ctx, p);

    // ---- 星空 ----
    this._drawStarfield(ctx, p);

    // ---- 地面 ----
    this.engine.rect(0, GROUND_Y, W, H - GROUND_Y, p.dark);
    this.engine.rect(0, GROUND_Y, W, 2, p.dim);

    // ---- 発射台 ----
    this._drawBattery(ctx, p);

    // ---- 都市 ----
    for (let i = 0; i < CITY_COUNT; i++) {
      this._drawCity(ctx, p, i);
    }

    // ---- 都市爆発エフェクト ----
    for (const cb of this.cityBlasts) {
      if (!cb) continue;
      ctx.save();
      ctx.globalAlpha = clamp(cb.t / 0.7, 0, 1) * 0.9;
      ctx.beginPath();
      ctx.arc(cb.x, cb.y, Math.max(1, cb.r), 0, Math.PI * 2);
      ctx.fillStyle = p.bad;
      ctx.fill();
      ctx.restore();
    }

    // ---- ミサイル ----
    for (const ms of this.missiles) {
      if (!ms || ms.done) continue;
      ctx.save();
      ctx.strokeStyle = ms.big ? p.warn : p.fg;
      ctx.lineWidth = ms.big ? 2.5 : 1.5;
      ctx.setLineDash(ms.big ? [6, 3] : []);
      ctx.beginPath();
      ctx.moveTo(BATTERY_X, BATTERY_Y);
      ctx.lineTo(ms.x, ms.y);
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.beginPath();
      ctx.arc(ms.x, ms.y, ms.big ? 4 : 2.5, 0, Math.PI * 2);
      ctx.fillStyle = ms.big ? p.warn : p.hi;
      ctx.fill();
      ctx.restore();
    }

    // ---- 隕石（岩石ポリゴン） ----
    for (const m of this.meteors) {
      if (!m) continue;

      // アイテム隕石
      if (m.isItem) {
        this._drawItemMeteor(ctx, p, m);
        continue;
      }

      const damageFrac = m.maxHp > 1 ? clamp(1 - m.hp / m.maxHp, 0, 1) : 0;
      const bodyColor  = m.boss ? p.warn : (m.fast ? p.hi : p.bad);

      // 軌跡
      const trailColor = m.boss ? p.warn : (m.fast ? p.hi : p.bad);
      for (let t = 0; t < m.trail.length; t++) {
        const pt = m.trail[t];
        if (!pt) continue;
        const alpha = ((t + 1) / (m.trail.length + 1)) * (m.fast ? 0.55 : (m.boss ? 0.55 : 0.35));
        ctx.save();
        ctx.globalAlpha = clamp(alpha, 0, 1);
        ctx.beginPath();
        ctx.arc(pt.x, pt.y, Math.max(1, m.r * 0.35), 0, Math.PI * 2);
        ctx.strokeStyle = trailColor;
        ctx.lineWidth = 1;
        ctx.stroke();
        ctx.restore();
      }

      // 岩石ポリゴン本体
      if (m.verts && m.verts.length >= 3) {
        const lineW    = clamp(1.8 - damageFrac * 0.8, 0.5, 2.5);
        const bodyAlpha = clamp(1 - damageFrac * 0.4, 0.3, 1);

        ctx.save();
        ctx.globalAlpha = clamp(bodyAlpha, 0, 1);
        ctx.translate(m.x, m.y);
        ctx.rotate(m.rot);

        // ボス：薄いフィル（暗く重厚な雰囲気）
        if (m.boss) {
          ctx.beginPath();
          ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
          for (let vi = 1; vi < m.verts.length; vi++) {
            ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
          }
          ctx.closePath();
          ctx.fillStyle = p.dark;
          ctx.globalAlpha = clamp(0.65 - damageFrac * 0.2, 0, 1);
          ctx.fill();
          ctx.globalAlpha = clamp(bodyAlpha, 0, 1);
        }

        // アウトライン
        ctx.beginPath();
        ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
        for (let vi = 1; vi < m.verts.length; vi++) {
          ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
        }
        ctx.closePath();
        ctx.strokeStyle = bodyColor;
        ctx.lineWidth = m.boss ? clamp(lineW * 2, 1, 4) : lineW;
        ctx.stroke();

        // ダメージ亀裂感
        if (damageFrac > 0.3 && m.verts.length >= 6) {
          ctx.globalAlpha = clamp(damageFrac * 0.5, 0, 1);
          ctx.beginPath();
          const v0 = m.verts[0];
          const v2 = m.verts[2];
          const v4 = m.verts[4];
          ctx.moveTo(v0.dx * 0.5, v0.dy * 0.5);
          ctx.lineTo(v2.dx * 0.5, v2.dy * 0.5);
          ctx.lineTo(v4.dx * 0.5, v4.dy * 0.5);
          ctx.strokeStyle = bodyColor;
          ctx.lineWidth = 0.7;
          ctx.stroke();
        }

        ctx.restore();

        // ボスのHP バー（大きいので常に表示）
        if (m.boss) {
          const barW  = clamp(m.r * 2.0, 80, W - 20);
          const barX  = clamp(m.x - barW / 2, 6, W - barW - 6);
          const barY  = clamp(m.y + m.r + 10, m.r + 10, GROUND_Y - 14);
          const barH  = 7;
          const hpFrac = clamp(m.hp / m.maxHp, 0, 1);
          ctx.save();
          ctx.fillStyle = p.dark;
          ctx.fillRect(barX, barY, barW, barH);
          ctx.fillStyle = damageFrac > 0.6 ? p.bad : p.warn;
          ctx.fillRect(barX, barY, Math.max(0, barW * hpFrac), barH);
          ctx.strokeStyle = p.mid;
          ctx.lineWidth = 1;
          ctx.strokeRect(barX, barY, barW, barH);
          ctx.restore();
          this.engine.text('BOSS', m.x, clamp(m.y - m.r - 20, 52, GROUND_Y - 40), 14, p.warn, 'center');
          // HP数値表示
          this.engine.text(m.hp + '/' + m.maxHp, m.x, clamp(m.y - m.r - 36, 52, GROUND_Y - 56), 11, p.dim, 'center');
        } else {
          // 通常隕石のHP ピップ
          if (m.maxHp >= 2) {
            const pipR   = 3;
            const pipGap = 8;
            const totalW = m.maxHp * pipR * 2 + (m.maxHp - 1) * (pipGap - pipR * 2);
            const startX = m.x - totalW / 2;
            const pipY   = m.y + m.r + 6;
            for (let k = 0; k < m.maxHp; k++) {
              const px    = startX + k * pipGap + pipR;
              const alive = k < m.hp;
              ctx.save();
              ctx.globalAlpha = alive ? 0.9 : 0.25;
              ctx.beginPath();
              ctx.arc(px, pipY, pipR, 0, Math.PI * 2);
              ctx.fillStyle = alive ? (m.fast ? p.hi : p.bad) : p.dim;
              ctx.fill();
              ctx.restore();
            }
          }
        }
      }
    }

    // ---- 爆発（grow then FADE OUT） ----
    for (const b of this.blasts) {
      if (!b) continue;

      let alpha;
      if (b.growing) {
        // 成長中：徐々に鮮明に
        alpha = clamp(b.r / b.maxR, 0, 1) * 0.9;
      } else {
        // フェードアウト（半径はキープ、アルファだけ落とす）
        alpha = clamp(b.fadeTimer / BLAST_FADE_SEC, 0, 1) * 0.85;
      }
      alpha = clamp(alpha, 0, 1);

      ctx.save();
      ctx.globalAlpha = alpha;

      // 外輪
      ctx.beginPath();
      ctx.arc(b.x, b.y, Math.max(1, b.r), 0, Math.PI * 2);
      ctx.strokeStyle = b.big ? p.warn : (b.isScatter ? p.hi : p.mid);
      ctx.lineWidth = b.big ? 3.5 : (b.isScatter ? 1.0 : 2.5);
      ctx.stroke();

      // ビッグ爆発：内輪
      if (b.big && b.r > 10) {
        ctx.beginPath();
        ctx.arc(b.x, b.y, Math.max(1, b.r * 0.65), 0, Math.PI * 2);
        ctx.strokeStyle = p.hi;
        ctx.lineWidth = 1;
        ctx.globalAlpha = clamp(alpha * 0.6, 0, 1);
        ctx.stroke();
      }

      // 内部フィル（薄く）
      ctx.beginPath();
      ctx.arc(b.x, b.y, Math.max(1, b.r * 0.55), 0, Math.PI * 2);
      ctx.fillStyle = b.big ? p.warn : (b.isScatter ? p.hi : p.mid);
      ctx.globalAlpha = clamp(alpha * 0.15, 0, 1);
      ctx.fill();

      ctx.restore();
    }

    // ---- ステージクリアオーバーレイ ----
    if (this._stageClearing) {
      const alpha = clamp(this._stageClearTimer / 2.2, 0, 1);
      ctx.save();
      ctx.globalAlpha = clamp(alpha * 0.88, 0, 1);
      ctx.fillStyle = p.dark;
      ctx.fillRect(0, H / 2 - 60, W, 120);
      ctx.restore();
      this.engine.text('STAGE ' + (this._stage + 1) + ' CLEAR!', W / 2, H / 2 - 42, 28, p.warn, 'center');
      // 次ステージのタイプを予告
      const nextStage = this._stage + 1;
      const nextTypes = STAGE_TYPES.filter(t => t !== 'NORMAL');
      const nextType  = nextTypes[nextStage % nextTypes.length];
      this.engine.text('NEXT: ' + nextType, W / 2, H / 2 + 4, 16, p.mid, 'center');
    }

    // ---- ゲームオーバーオーバーレイ ----
    if (this.dead) {
      this.engine.rect(0, H / 2 - 90, W, 200, p.dark);
      this.engine.stroke(0, H / 2 - 90, W, 200, p.bad, 2);
      this.engine.text('GAME OVER', W / 2, H / 2 - 78, 32, p.bad, 'center');
      this.engine.text('SCORE  ' + this.score, W / 2, H / 2 - 32, 20, p.fg, 'center');
      this.engine.text('BEST   ' + this.high,  W / 2, H / 2 - 4,  16, p.dim, 'center');
      this.engine.text('TAP TO RETRY', W / 2, H / 2 + 38, 16, p.mid, 'center');
      this.engine.text('BACK: MENU',   W / 2, H / 2 + 62, 13, p.dim, 'center');
    }

    // ---- クールダウンインジケータ ----
    if (this._fireCooldown > 0 && !this.dead) {
      const frac = clamp(1 - this._fireCooldown / FIRE_COOLDOWN, 0, 1);
      const barW = 28;
      const barX = BATTERY_X - barW / 2;
      const barY = BATTERY_Y - 24;
      ctx.save();
      ctx.fillStyle = p.dark;
      ctx.fillRect(barX, barY, barW, 3);
      ctx.fillStyle = p.mid;
      ctx.fillRect(barX, barY, Math.max(0, barW * frac), 3);
      ctx.restore();
    }
  }

  // ---- アイテム隕石の描画 ----
  _drawItemMeteor(ctx, p, m) {
    if (!m.verts || m.verts.length < 3) return;
    // パルス（点滅アニメ）
    const pulse = 0.75 + 0.25 * Math.sin(this._elapsed * 5.0);

    ctx.save();
    ctx.globalAlpha = clamp(pulse, 0, 1);
    ctx.translate(m.x, m.y);
    ctx.rotate(m.rot);

    // 外周ポリゴン（シアン色で目立たせる）
    ctx.beginPath();
    ctx.moveTo(m.verts[0].dx, m.verts[0].dy);
    for (let vi = 1; vi < m.verts.length; vi++) {
      ctx.lineTo(m.verts[vi].dx, m.verts[vi].dy);
    }
    ctx.closePath();
    ctx.strokeStyle = p.hi;
    ctx.lineWidth = 2.5;
    ctx.stroke();
    // 内部うっすらフィル
    ctx.fillStyle = p.hi;
    ctx.globalAlpha = clamp(pulse * 0.12, 0, 1);
    ctx.fill();

    ctx.restore();

    // 中心アイコン（ラベル）
    ctx.save();
    ctx.globalAlpha = clamp(pulse, 0, 1);
    const label = m.itemType ? m.itemType[0] : '?'; // 頭文字1文字
    this.engine.text(label, m.x, m.y - 6, 13, p.warn, 'center');
    ctx.restore();
  }

  // ---- パワーアップHUD ----
  _drawPowerupHUD(ctx, p) {
    // 右下のHUDエリアに小さく表示
    const pu = this._powerups;
    const parts = [];
    if (pu.missileMax > BASE_MAX_MISSILES) parts.push('ML' + pu.missileMax);
    if (pu.blastDamage > BLAST_DAMAGE_NORMAL_BASE) parts.push('PW' + pu.blastDamage);
    if (pu.blastRadiusAdd > 0) parts.push('WD' + (pu.blastRadiusAdd / 12 | 0));
    if (pu.scatter) parts.push('SC');

    if (parts.length === 0) return;
    const label = parts.join(' ');
    // 右上エリアの下（スコアの下）
    this.engine.text(label, W - 12, 44, 10, p.hi, 'right');
  }

  // ---- ビッグブラスト HUD ----
  _drawBigChargeHUD(ctx, p) {
    const baseX = W / 2 - 40;
    const baseY = 52;
    const b = this._bigBtnRect();
    if (this._bigArmed) {
      this.engine.stroke(b.x, b.y, b.w, b.h, p.hi, 2);
      this.engine.text('TAP SKY', b.x + b.w + 6, baseY, 11, p.hi, 'left');
    }
    this.engine.text('BIG:', baseX, baseY, 13, this._bigArmed ? p.hi : p.dim, 'left');
    for (let i = 0; i < BIG_CHARGES_MAX; i++) {
      const cx = baseX + 44 + i * 18;
      const cy = baseY + 6;
      ctx.save();
      ctx.beginPath();
      ctx.arc(cx, cy, 6, 0, Math.PI * 2);
      if (i < this._bigCharges) {
        ctx.fillStyle = p.warn;
        ctx.fill();
      } else {
        ctx.strokeStyle = p.dim;
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
      ctx.restore();
    }
    if (this._bigCharges < BIG_CHARGES_MAX) {
      const gaugeX = baseX;
      const gaugeY = baseY + 18;
      const gaugeW = 96;
      const frac   = clamp(this._bigRecharge / BIG_RECHARGE_SEC, 0, 1);
      this.engine.rect(gaugeX, gaugeY, gaugeW, 4, p.dark);
      this.engine.rect(gaugeX, gaugeY, Math.floor(gaugeW * frac), 4, p.warn);
    }
  }

  // ---- 星空 ----
  _drawStarfield(ctx, p) {
    ctx.save();
    ctx.fillStyle = p.dim;
    const stars = [
      [30,80],[90,55],[150,100],[220,60],[280,90],[340,70],
      [60,140],[130,170],[200,130],[260,155],[320,120],
      [45,210],[110,240],[180,200],[250,220],[315,180],
      [70,300],[160,280],[230,310],[300,290],
    ];
    for (const [sx, sy] of stars) {
      ctx.beginPath();
      ctx.arc(sx, sy, 1, 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }

  // ---- 発射台 ----
  _drawBattery(ctx, p) {
    const bx = BATTERY_X;
    const by = BATTERY_Y;
    this.engine.rect(bx - 14, by - 2, 28, 8, p.mid);
    ctx.save();
    ctx.fillStyle = p.fg;
    ctx.beginPath();
    ctx.moveTo(bx, by - 16);
    ctx.lineTo(bx - 5, by - 2);
    ctx.lineTo(bx + 5, by - 2);
    ctx.closePath();
    ctx.fill();
    ctx.restore();
  }

  // ---- 都市 ----
  _drawCity(ctx, p, idx) {
    const x = CITY_XS[idx];
    const y = GROUND_Y - CITY_H;
    if (!this.cities[idx]) {
      this.engine.rect(x + 2, y + CITY_H - 5, CITY_W - 4, 5, p.dim);
      this.engine.text('x', x + CITY_W / 2, y + CITY_H - 14, 11, p.bad, 'center');
      return;
    }
    this.engine.rect(x, y, CITY_W, CITY_H, p.mid);
    this.engine.rect(x, y, CITY_W, 3, p.fg);
    this.engine.rect(x + 4, y + 6, 6, 6, p.bg);
    this.engine.rect(x + 14, y + 6, 6, 6, p.bg);
    this.engine.rect(x + 5, y + 7, 4, 4, p.hi);
    this.engine.rect(x + 15, y + 7, 4, 4, p.hi);
  }
}

// ---- 都市X座標（均等配置）----
const CITY_SPACING = (W - CITY_W * CITY_COUNT) / (CITY_COUNT + 1);
const CITY_XS = Array.from({ length: CITY_COUNT }, (_, i) =>
  Math.floor(CITY_SPACING + i * (CITY_W + CITY_SPACING))
);

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/games/lander.js ----
(function(){
// LANDER: Control attitude with RCS thrusters and soft-land on the lunar surface.
// Reaction-thruster convention (physically correct):
//   LEFT  button (x < 120): right-side thruster fires RIGHT -> reaction pushes nose LEFT  -> craft rotates CW  (omega +)
//   RIGHT button (x > 240): left-side thruster fires LEFT  -> reaction pushes nose RIGHT -> craft rotates CCW (omega -)
//   THRUST button (center): main engine fires along craft's up-axis.
// Safe landing on the pad = STAGE CLEAR. Crash = GAME OVER.

const meta = {
  id: 'lander',
  title: 'LANDER',
  desc: 'Attitude control: soft-land on the lunar surface',
  glyph: '^',
};

// ---- Physics tuning constants ----
// GRAVITY_BASE: Stage-1 gravity in px/s^2. Craft descends ~0.6 px/s^2 -> reaches floor in ~30s from y=90.
// NO translational damping (VEL_DAMP removed). Motion is purely Newtonian.
// ANG_DAMP: mild angular drag so the pilot can stabilize attitude. Translational velocity is undamped.
const GRAVITY_BASE      = 0.6;   // px/s^2 — gentle but real; craft visibly falls in ~25-35 s
const THRUST_ACCEL      = 8.0;   // main engine thrust (px/s^2)
const ANG_ACCEL         = 40.0;  // RCS angular acceleration (deg/s^2)
const ANG_DAMP          = 0.88;  // angular velocity damping per second (exponential decay)
// NO VEL_DAMP — translational motion is undamped (purely Newtonian)
const FUEL_MAX          = 100;
const FUEL_RATE_MAIN    = 7;
const FUEL_RATE_RCS     = 2;
const SAFE_VY           = 14;
const SAFE_VX           = 8;
const SAFE_ANGLE        = 18;
const SAFE_OMEGA        = 12;
const PAD_W_BASE        = 54;
const TERRAIN_SEGS      = 18;
const LANDER_START_Y    = 90;
const GUIDE_THRESHOLD   = 30;
const GUIDE_PTS         = 32;

// Control zones (logical coordinates 0..360)
const ZONE_L_MAX  = 120;  // left button: x < ZONE_L_MAX
const ZONE_R_MIN  = 240;  // right button: x > ZONE_R_MIN
const CONTROL_Y_MIN = 52; // ignore pointer input above this Y (BACK button zone)

// Bottom button bar geometry
const BTN_Y   = H - 80;  // top of button bar
const BTN_H   = 80;       // height of button bar

// ---- Stage difficulty scaling ----
// Stage 1: low gravity, no obstacles.
// Stage 2+: gravity increases per stage; floating obstacles added and multiplied.
function stageParams(stage) {
  const s = Math.min(stage, 8);
  return {
    // gravity increases ~12% per stage beyond stage 1
    gravity:      GRAVITY_BASE * (1 + (s - 1) * 0.12),
    padW:         Math.max(24, PAD_W_BASE - (s - 1) * 4),
    stageBonus:   s * 50,
    // obstacles: 0 in stage 1, then 2 + (s-2) extras per stage
    obstacleCount: s <= 1 ? 0 : 2 + (s - 2),
    // obstacle drift speed scales with stage
    obstacleSpeed: 12 + (s - 1) * 4,
  };
}

// ---- Terrain generation ----
function buildTerrain(padW) {
  const segW    = W / TERRAIN_SEGS;
  const FLOOR_Y   = 608;
  const FLOOR_MIN = 525;
  const pts       = [];

  // Pick one random segment for the landing pad
  const available = [];
  for (let i = 2; i < TERRAIN_SEGS - 3; i++) available.push(i);
  const padSeg = available[Math.floor(Math.random() * available.length)];

  for (let i = 0; i <= TERRAIN_SEGS; i++) {
    const x = i * segW;
    let y;
    if (i === 0 || i === TERRAIN_SEGS) {
      y = FLOOR_Y;
    } else {
      y = FLOOR_MIN + Math.random() * (FLOOR_Y - FLOOR_MIN);
    }
    pts.push({ x, y });
  }

  // Flatten the pad segment
  const midX  = (padSeg + 0.5) * segW;
  const flatY = FLOOR_MIN + 20 + Math.random() * 50;
  const lx    = midX - padW / 2;
  pts[padSeg].y     = flatY;
  pts[padSeg + 1].y = flatY;
  if (padSeg > 0)                  pts[padSeg - 1].y = (pts[padSeg - 1].y + flatY) / 2;
  if (padSeg + 2 <= TERRAIN_SEGS)  pts[padSeg + 2].y = (pts[padSeg + 2].y + flatY) / 2;

  const pad = { x: lx, y: flatY, w: padW };
  return { pts, pad };
}

// ---- Stars (background) ----
function buildStars(count) {
  const stars = [];
  for (let i = 0; i < count; i++) {
    stars.push({
      x: Math.random() * W,
      y: 20 + Math.random() * 460,
      r: Math.random() < 0.2 ? 2 : 1,
    });
  }
  return stars;
}

// ---- Descent trajectory guide (parabolic from start to pad center) ----
function buildGuide(startX, startY, pad, numPts) {
  const targetX = pad.x + pad.w / 2;
  const targetY = pad.y;
  const pts     = [];
  for (let i = 0; i <= numPts; i++) {
    const t = i / numPts;
    pts.push({
      x: startX + (targetX - startX) * t,
      y: startY + (targetY - startY) * (t * t),
    });
  }
  return pts;
}

// ---- Floating obstacles (stages 2+) ----
// Obstacles drift horizontally. They appear in the mid-descent zone (y 150-480)
// and bounce off the left/right walls. Touching one = crash.
function buildObstacles(count, speed) {
  const obs = [];
  if (count <= 0) return obs;
  for (let i = 0; i < count; i++) {
    // Spread evenly through descent zone, avoid spawning right at the start
    const yBand   = 150 + (i / count) * 300 + Math.random() * 60;
    const vxSign  = Math.random() < 0.5 ? 1 : -1;
    const r       = 10 + Math.floor(Math.random() * 8); // radius 10-17
    obs.push({
      x:  30 + Math.random() * (W - 60),
      y:  Math.max(150, Math.min(480, yBand)),
      vx: (speed * 0.6 + Math.random() * speed * 0.8) * vxSign,
      r,
    });
  }
  return obs;
}

class Game extends Scene {

  enter() {
    this.high       = (this.engine.storage.getHigh(meta.id) || 0);
    this.totalScore = 0;
    this.stage      = 1;
    this.state      = 'play';
    this._initStage();
  }

  // ---- Initialize one stage ----
  _initStage() {
    this.state    = 'play';
    this.fuel     = FUEL_MAX;
    this.angle    = (Math.random() - 0.5) * 8;  // tiny initial tilt (degrees)
    this.omega    = 0;                           // angular velocity (deg/s)
    this.x        = W / 2 + (Math.random() - 0.5) * 50;
    this.y        = LANDER_START_Y;
    this.vx       = (Math.random() - 0.5) * 4;  // near-zero initial horizontal speed
    this.vy       = 2;                           // slow initial downward speed

    this._thrustMain = false;
    this._thrustRcsL = false;
    this._thrustRcsR = false;

    const sp       = stageParams(this.stage);
    this._gravity  = sp.gravity;
    this._padW     = sp.padW;

    const terrain     = buildTerrain(this._padW);
    this.terrainPts   = terrain.pts;
    this.pad          = terrain.pad;
    this.stars        = this.stars || buildStars(40);

    this.guidePts = buildGuide(this.x, this.y, this.pad, GUIDE_PTS);

    this._guideDevTotal = 0;
    this._guideDevCount = 0;
    this._stageScore    = 0;
    this._guideBonus    = 0;
    this.particles      = [];

    // Floating obstacles (stage 2+)
    this.obstacles = buildObstacles(sp.obstacleCount, sp.obstacleSpeed);

    this._keys = this._keys || { left: false, right: false, up: false };
  }

  // ---- Distance to nearest guide point ----
  _distToGuide(x, y) {
    let minDist = Infinity;
    const pts = this.guidePts;
    if (!pts) return Infinity;
    for (let i = 0; i < pts.length; i++) {
      const dx = x - pts[i].x;
      const dy = y - pts[i].y;
      const d  = Math.sqrt(dx * dx + dy * dy);
      if (d < minDist) minDist = d;
    }
    return minDist;
  }

  // ---- Keyboard discrete input ----
  onInput(action, data) {
    if (this.state === 'cleared') {
      if (action === 'tap' || action === 'confirm') {
        this.stage += 1;
        this._initStage();
      }
      if (action === 'back') { this.engine.toMenu(); }
      return;
    }
    if (this.state === 'gameover') {
      if (action === 'tap' || action === 'confirm') {
        this.totalScore = 0;
        this.stage      = 1;
        this._initStage();
      }
      if (action === 'back') { this.engine.toMenu(); }
      return;
    }
    if (action === 'back') { this.engine.toMenu(); return; }

    if (this._keys) {
      if (action === 'left')    this._keys.left  = true;
      if (action === 'right')   this._keys.right = true;
      if (action === 'up')      this._keys.up    = true;
      if (action === 'confirm') this._keys.up    = true;
    }
  }

  // ---- Per-frame logic ----
  update(dt) {
    if (typeof dt !== 'number' || dt <= 0 || dt > 0.1) dt = 0.016;

    if (this.state !== 'play') {
      this._updateParticles(dt);
      if (this._keys) { this._keys.left = false; this._keys.right = false; this._keys.up = false; }
      return;
    }

    const ptr = this.engine.pointer;

    // ---- Read control inputs ----
    // Pointer press-and-hold in the bottom button bar (y > BTN_Y) is the primary control.
    // Top strip y < CONTROL_Y_MIN is ignored to avoid conflicting with the BACK button.
    this._thrustMain = false;
    this._thrustRcsL = false;
    this._thrustRcsR = false;

    if (ptr.down && ptr.y > CONTROL_Y_MIN) {
      if (ptr.x < ZONE_L_MAX) {
        // LEFT button pressed
        this._thrustRcsL = true;
      } else if (ptr.x > ZONE_R_MIN) {
        // RIGHT button pressed
        this._thrustRcsR = true;
      } else {
        // CENTER: main engine
        this._thrustMain = true;
      }
    }

    // Keyboard (one-shot pulse per frame)
    if (this._keys) {
      if (this._keys.left)  this._thrustRcsL = true;
      if (this._keys.right) this._thrustRcsR = true;
      if (this._keys.up)    this._thrustMain  = true;
      this._keys.left  = false;
      this._keys.right = false;
      this._keys.up    = false;
    }

    // ---- RCS attitude jets — reaction-thruster convention ----
    // Physical convention: the nozzle FIRES toward the button side; Newton's 3rd law
    // pushes the craft nose the OPPOSITE way.
    //
    // LEFT button  -> left-side nozzle fires leftward -> nose pushed RIGHT -> CW rotation
    //   omega += ANG_ACCEL * dt  (positive omega -> angle increases -> ctx.rotate(+rad) -> CW on screen)
    //
    // RIGHT button -> right-side nozzle fires rightward -> nose pushed LEFT -> CCW rotation
    //   omega -= ANG_ACCEL * dt  (negative omega -> angle decreases -> ctx.rotate(-rad) -> CCW on screen)
    //
    // Keyboard: ArrowLeft maps to _thrustRcsL (same CW convention).
    //           ArrowRight maps to _thrustRcsR (same CCW convention).
    if (this._thrustRcsL && this.fuel > 0) {
      this.omega += ANG_ACCEL * dt;   // CW: nose tilts RIGHT
      this.fuel   = Math.max(0, this.fuel - FUEL_RATE_RCS * dt);
    }
    if (this._thrustRcsR && this.fuel > 0) {
      this.omega -= ANG_ACCEL * dt;   // CCW: nose tilts LEFT
      this.fuel   = Math.max(0, this.fuel - FUEL_RATE_RCS * dt);
    }

    // ---- Angular damping (mild drag so craft can be stabilized) ----
    this.omega *= Math.pow(ANG_DAMP, dt);

    // ---- Integrate omega -> angle ----
    this.angle += this.omega * dt;
    // Normalize to -180..180
    this.angle  = ((this.angle + 180) % 360 + 360) % 360 - 180;

    // ---- Main engine: thrust along craft's up-axis ----
    // angle=0 => pointing straight up. craft up vector in screen coords:
    //   when angle=0, "up" is -Y (screen). ctx.rotate(+rad) rotates CW.
    //   craft up unit vector: (-sin(angle_rad), -cos(angle_rad)) in canvas (x,y).
    if (this._thrustMain && this.fuel > 0) {
      const rad = this.angle * Math.PI / 180;
      this.vx  += (-Math.sin(rad)) * THRUST_ACCEL * dt;
      this.vy  += (-Math.cos(rad)) * THRUST_ACCEL * dt;
      this.fuel = Math.max(0, this.fuel - FUEL_RATE_MAIN * dt);
    }

    // ---- Gravity (straight down = +Y in canvas) ----
    // NO translational damping. Purely Newtonian: only gravity and engine thrust change velocity.
    this.vy += this._gravity * dt;

    // ---- Position update ----
    this.x += this.vx * dt;
    this.y += this.vy * dt;

    // ---- Horizontal clamp (weak bounce at edges) ----
    const PAD = 14;
    if (this.x < PAD)     { this.x = PAD;     this.vx =  Math.abs(this.vx) * 0.3; }
    if (this.x > W - PAD) { this.x = W - PAD; this.vx = -Math.abs(this.vx) * 0.3; }
    // Top clamp
    if (this.y < 60) { this.y = 60; this.vy = Math.max(0, this.vy); }

    // ---- Guide deviation tracking (upper half only) ----
    if (this.y < 420) {
      this._guideDevTotal += this._distToGuide(this.x, this.y);
      this._guideDevCount += 1;
    }

    // ---- Update floating obstacles (stages 2+) ----
    if (this.obstacles && this.obstacles.length > 0) {
      for (const ob of this.obstacles) {
        ob.x += ob.vx * dt;
        // Bounce off walls
        if (ob.x - ob.r < 0)     { ob.x = ob.r;     ob.vx = Math.abs(ob.vx); }
        if (ob.x + ob.r > W)     { ob.x = W - ob.r; ob.vx = -Math.abs(ob.vx); }
      }
      // Check collision with lander (circle vs. point, craft body ~16x18 -> use 14px radius)
      const craftR = 14;
      for (const ob of this.obstacles) {
        const dx = this.x - ob.x;
        const dy = this.y - ob.y;
        if (Math.sqrt(dx * dx + dy * dy) < craftR + ob.r) {
          // Hit an obstacle — crash
          this._explode();
          this.engine.audio.bad();
          this.totalScore += Math.round((this.fuel || 0) * 2);
          if (this.totalScore > this.high) {
            this.high = this.totalScore;
            this.engine.storage.setHigh(meta.id, this.high);
          }
          this.state = 'gameover';
          return;
        }
      }
    }

    // ---- Terrain collision ----
    this._checkCollision();
  }

  // ---- Collision & landing check ----
  _checkCollision() {
    const terrainY = this._terrainYAt(this.x);
    const footY    = this.y + 16;

    if (footY < terrainY) return;

    const onPad   = (this.x >= this.pad.x && this.x <= this.pad.x + this.pad.w);
    const absAngle = Math.abs(((this.angle + 180) % 360 + 360) % 360 - 180);
    const absOmega = Math.abs(this.omega);

    const safeLand = onPad &&
                     Math.abs(this.vy) <= SAFE_VY &&
                     Math.abs(this.vx) <= SAFE_VX &&
                     absAngle          <= SAFE_ANGLE &&
                     absOmega          <= SAFE_OMEGA;

    if (safeLand) {
      this.y  = terrainY - 16;
      this.vx = 0; this.vy = 0; this.omega = 0;

      const sp        = stageParams(this.stage);
      const fuelBonus = Math.round(this.fuel * 10);
      const softBonus = Math.round(Math.max(0, SAFE_VY - Math.abs(this.vy)) * 6);
      const uprBonus  = Math.round(Math.max(0, SAFE_ANGLE - absAngle) * 4);
      let guideBonus  = 0;
      if (this._guideDevCount > 0) {
        const avgDev = this._guideDevTotal / this._guideDevCount;
        guideBonus   = Math.round(Math.max(0, 200 - avgDev * 2.5));
      }
      this._guideBonus  = guideBonus;
      this._stageScore  = fuelBonus + softBonus + uprBonus + guideBonus + sp.stageBonus;
      this.totalScore  += this._stageScore;

      if (this.totalScore > this.high) {
        this.high = this.totalScore;
        this.engine.storage.setHigh(meta.id, this.high);
      }

      this.engine.audio.good();
      this.state = 'cleared';

    } else {
      this._explode();
      this.engine.audio.bad();

      this.totalScore += Math.round((this.fuel || 0) * 2);

      if (this.totalScore > this.high) {
        this.high = this.totalScore;
        this.engine.storage.setHigh(meta.id, this.high);
      }

      this.state = 'gameover';
    }
  }

  // ---- Explosion particles ----
  _explode() {
    this.particles = [];
    for (let i = 0; i < 28; i++) {
      const spd = 20 + Math.random() * 60;
      const dir = Math.random() * Math.PI * 2;
      this.particles.push({
        x:    this.x,
        y:    this.y,
        vx:   Math.cos(dir) * spd,
        vy:   Math.sin(dir) * spd - 25,
        life: 0.7 + Math.random() * 1.0,
        max:  1.7,
      });
    }
  }

  _updateParticles(dt) {
    if (!this.particles) return;
    for (const pt of this.particles) {
      pt.x    += pt.vx * dt;
      pt.y    += pt.vy * dt;
      pt.vy   += (this._gravity || GRAVITY_BASE) * dt;
      pt.life -= dt;
    }
    this.particles = this.particles.filter(pt => pt.life > 0);
  }

  // ---- Linear interpolation of terrain Y at given X ----
  _terrainYAt(x) {
    const pts = this.terrainPts;
    if (!pts || pts.length < 2) return H;
    for (let i = 0; i < pts.length - 1; i++) {
      if (x >= pts[i].x && x <= pts[i + 1].x) {
        const t = (x - pts[i].x) / (pts[i + 1].x - pts[i].x);
        return pts[i].y + t * (pts[i + 1].y - pts[i].y);
      }
    }
    return H;
  }

  // ---- Main render ----
  render(ctx) {
    const p = P();

    // Stars
    if (this.stars) {
      for (const s of this.stars) {
        ctx.fillStyle = s.r > 1 ? p.dim : p.dark;
        ctx.fillRect(s.x, s.y, s.r, s.r);
      }
    }

    // Descent trajectory guide
    this._drawGuide(ctx);

    // Floating obstacles (stages 2+)
    this._drawObstacles(ctx);

    // Terrain
    if (this.terrainPts && this.terrainPts.length > 0) {
      ctx.fillStyle = p.dark;
      ctx.beginPath();
      ctx.moveTo(0, H);
      for (const pt of this.terrainPts) ctx.lineTo(pt.x, pt.y);
      ctx.lineTo(W, H);
      ctx.closePath();
      ctx.fill();

      ctx.strokeStyle = p.dim;
      ctx.lineWidth   = 2;
      ctx.beginPath();
      for (let i = 0; i < this.terrainPts.length; i++) {
        const pt = this.terrainPts[i];
        if (i === 0) ctx.moveTo(pt.x, pt.y);
        else         ctx.lineTo(pt.x, pt.y);
      }
      ctx.stroke();
    }

    // Landing pad
    if (this.pad) {
      const pd = this.pad;
      ctx.fillStyle = p.fg;
      ctx.fillRect(pd.x, pd.y, pd.w, 4);
      ctx.fillStyle = p.mid;
      ctx.fillRect(pd.x,            pd.y, 4, 10);
      ctx.fillRect(pd.x + pd.w - 4, pd.y, 4, 10);
      // Flag pole
      ctx.fillStyle = p.mid;
      ctx.fillRect(pd.x + pd.w / 2 - 1, pd.y - 22, 2, 22);
      ctx.fillStyle = p.warn;
      ctx.fillRect(pd.x + pd.w / 2 + 1, pd.y - 20, 12, 9);
      this.engine.text('PAD', pd.x + pd.w / 2, pd.y - 38, 10, p.mid, 'center');
    }

    // Explosion particles
    if (this.particles) {
      for (const pt of this.particles) {
        const t = Math.max(0, Math.min(1, pt.life / (pt.max || 1.7)));
        ctx.fillStyle = t > 0.5 ? p.warn : p.bad;
        const r = Math.max(1, Math.round(t * 4));
        ctx.fillRect(pt.x - r / 2, pt.y - r / 2, r, r);
      }
    }

    // Lander craft
    if (this.state !== 'gameover' || (this.particles && this.particles.length > 0)) {
      if (this.state === 'play' || this.state === 'cleared') {
        this._drawLander(ctx, this.x, this.y, this.angle);
      }
    }

    // HUD
    this._drawHUD(ctx);

    // Bottom button controls
    this._drawButtons(ctx);

    // Result overlays
    if (this.state === 'cleared') {
      this._drawClearScreen(ctx);
    } else if (this.state === 'gameover') {
      this._drawGameOver(ctx);
    }
  }

  // ---- Floating obstacles ----
  _drawObstacles(ctx) {
    if (!this.obstacles || this.obstacles.length === 0) return;
    const p = P();
    for (const ob of this.obstacles) {
      // Draw as a jagged rock/asteroid (octagon-ish)
      ctx.save();
      ctx.translate(ob.x, ob.y);
      ctx.fillStyle   = p.dark;
      ctx.strokeStyle = p.bad;
      ctx.lineWidth   = 2;
      ctx.beginPath();
      const sides = 7;
      for (let i = 0; i < sides; i++) {
        // Slightly irregular radius for rock feel
        const jitter = 0.75 + (((i * 37 + 13) % 7) / 7) * 0.5;
        const angle  = (i / sides) * Math.PI * 2;
        const rx     = Math.cos(angle) * ob.r * jitter;
        const ry     = Math.sin(angle) * ob.r * jitter;
        if (i === 0) ctx.moveTo(rx, ry);
        else         ctx.lineTo(rx, ry);
      }
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
      // Small warning highlight
      ctx.fillStyle   = p.warn;
      ctx.globalAlpha = Math.max(0, Math.min(1, 0.55));
      ctx.fillRect(ob.x - 2 - ob.x + ob.x, -2, 4, 4);
      ctx.globalAlpha = 1;
      ctx.restore();
    }
  }

  // ---- Descent trajectory guide (dashed line) ----
  _drawGuide(ctx) {
    const p   = P();
    const pts = this.guidePts;
    if (!pts || pts.length < 2) return;

    const dist     = this.state === 'play' ? this._distToGuide(this.x, this.y) : Infinity;
    const onCourse = (dist <= GUIDE_THRESHOLD);

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, onCourse ? 0.85 : 0.28));
    ctx.strokeStyle = onCourse ? p.hi : p.warn;
    ctx.lineWidth   = onCourse ? 2 : 1;
    ctx.setLineDash(onCourse ? [5, 5] : [4, 8]);
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
    ctx.stroke();
    ctx.setLineDash([]);

    // Diamond marker at target
    const last = pts[pts.length - 1];
    ctx.fillStyle   = onCourse ? p.hi : p.warn;
    ctx.globalAlpha = Math.max(0, Math.min(1, onCourse ? 0.9 : 0.45));
    ctx.beginPath();
    ctx.moveTo(last.x,     last.y - 7);
    ctx.lineTo(last.x + 6, last.y);
    ctx.lineTo(last.x,     last.y + 7);
    ctx.lineTo(last.x - 6, last.y);
    ctx.closePath();
    ctx.fill();
    ctx.restore();

    if (onCourse && this.state === 'play') {
      this._drawOnCourseIndicator(ctx);
    }
  }

  // ---- ON COURSE glow indicator ----
  _drawOnCourseIndicator(ctx) {
    const p = P();
    ctx.save();
    ctx.globalAlpha  = Math.max(0, Math.min(1, 0.45));
    ctx.strokeStyle  = p.hi;
    ctx.lineWidth    = 3;
    ctx.shadowColor  = p.hi;
    ctx.shadowBlur   = 8;
    ctx.beginPath();
    ctx.arc(this.x, this.y, 20, 0, Math.PI * 2);
    ctx.stroke();
    ctx.restore();

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.9));
    this.engine.text('ON COURSE', W / 2, 72, 12, p.hi, 'center');
    ctx.restore();
  }

  // ---- Lander craft with 4 RCS nozzles ----
  // Rotation math (ctx.rotate convention):
  //   ctx.rotate(+rad) = clockwise (CW) on screen
  //   ctx.rotate(-rad) = counter-clockwise (CCW) on screen
  //
  //   omega > 0 -> angle increases -> ctx.rotate(+rad) -> CW on screen (nose tilts RIGHT)
  //   omega < 0 -> angle decreases -> ctx.rotate(-rad) -> CCW on screen (nose tilts LEFT)
  //
  //   LEFT  button -> omega += -> CW  (nose tilts right)   LEFT nozzle fires left -> reaction right
  //   RIGHT button -> omega -= -> CCW (nose tilts left)   RIGHT nozzle fires right -> reaction left
  //
  // The FLAME is drawn on the FIRING nozzle side, consistent with actual exhaust direction.
  _drawLander(ctx, x, y, angleDeg) {
    const p   = P();
    if (typeof x !== 'number' || typeof y !== 'number') return;
    const rad = ((angleDeg || 0) * Math.PI / 180);

    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(rad);  // positive rad = CW on canvas; negative = CCW

    // Main engine flame (bottom nozzle, fires downward in body space)
    if (this._thrustMain && this.fuel > 0) {
      const fl = 10 + Math.random() * 10;
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(-6, 9);
      ctx.lineTo(0,  9 + fl);
      ctx.lineTo(6,  9);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = p.hi;
      ctx.beginPath();
      ctx.moveTo(-3, 9);
      ctx.lineTo(0,  9 + fl * 0.5);
      ctx.lineTo(3,  9);
      ctx.closePath();
      ctx.fill();
    }

    // Body
    ctx.fillStyle   = p.mid;
    ctx.fillRect(-8, -10, 16, 18);
    ctx.strokeStyle = p.fg;
    ctx.lineWidth   = 1.5;
    ctx.strokeRect(-8, -10, 16, 18);

    // Cabin window
    ctx.fillStyle = p.hi;
    ctx.fillRect(-4, -8, 8, 7);

    // Left landing leg
    ctx.strokeStyle = p.mid;
    ctx.lineWidth   = 2;
    ctx.beginPath(); ctx.moveTo(-7, 8);   ctx.lineTo(-14, 16); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(-14, 16); ctx.lineTo(-18, 16); ctx.stroke();

    // Right landing leg
    ctx.beginPath(); ctx.moveTo(7, 8);    ctx.lineTo(14, 16);  ctx.stroke();
    ctx.beginPath(); ctx.moveTo(14, 16);  ctx.lineTo(18, 16);  ctx.stroke();

    // Main engine nozzle (bottom center)
    ctx.fillStyle = p.dark;
    ctx.fillRect(-5, 9, 10, 5);
    ctx.strokeStyle = (this._thrustMain && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 1;
    ctx.strokeRect(-5, 9, 10, 5);

    // LEFT RCS nozzle (body left side, upper area)
    // LEFT button fires LEFT nozzle to the LEFT. Reaction: nose goes RIGHT = CW = omega +.
    // Flame jets LEFT from left nozzle.
    ctx.fillStyle = p.dark;
    ctx.fillRect(-12, -6, 4, 4);
    if (this._thrustRcsL && this.fuel > 0) {
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(-12, -4);
      ctx.lineTo(-12 - (5 + Math.random() * 5), -2);
      ctx.lineTo(-12, -6 + 1);
      ctx.closePath();
      ctx.fill();
    }
    ctx.strokeStyle = (this._thrustRcsL && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(-12, -6, 4, 4);

    // RIGHT RCS nozzle (body right side, upper area)
    // RIGHT button fires RIGHT nozzle to the RIGHT. Reaction: nose goes LEFT = CCW = omega -.
    // Flame jets RIGHT from right nozzle.
    ctx.fillStyle = p.dark;
    ctx.fillRect(8, -6, 4, 4);
    if (this._thrustRcsR && this.fuel > 0) {
      ctx.fillStyle = p.warn;
      ctx.beginPath();
      ctx.moveTo(12, -4);
      ctx.lineTo(12 + (5 + Math.random() * 5), -2);
      ctx.lineTo(12, -6 + 1);
      ctx.closePath();
      ctx.fill();
    }
    ctx.strokeStyle = (this._thrustRcsR && this.fuel > 0) ? p.warn : p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(8, -6, 4, 4);

    // Top attitude nozzle (visual reference)
    ctx.fillStyle   = p.dark;
    ctx.fillRect(-3, -14, 6, 4);
    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 0.8;
    ctx.strokeRect(-3, -14, 6, 4);

    ctx.restore();
  }

  // ---- HUD (top area, x >= 52 to clear the BACK button) ----
  _drawHUD(ctx) {
    const p = P();

    this.engine.text('LANDER', 52, 8, 16, p.fg, 'left');
    this.engine.text('ST.' + this.stage, 52, 26, 12, p.mid, 'left');
    this.engine.text('HI ' + (this.high || 0),      W - 8, 8,  12, p.dim, 'right');
    this.engine.text('TOT ' + this.totalScore,       W - 8, 22, 12, p.mid, 'right');

    // Fuel bar
    const bx = 52, by = 44, bw = 110, bh = 10;
    this.engine.rect(bx, by, bw, bh, p.dark);
    const fr   = Math.max(0, Math.min(1, (this.fuel || 0) / FUEL_MAX));
    const fclr = fr > 0.4 ? p.mid : fr > 0.15 ? p.warn : p.bad;
    if (fr > 0) this.engine.rect(bx, by, Math.round(bw * fr), bh, fclr);
    this.engine.stroke(bx, by, bw, bh, p.dim, 1);
    this.engine.text('FUEL', bx + bw + 4, by, 10, p.dim, 'left');

    if (this.state !== 'play') return;

    // Vertical speed
    const vy    = this.vy || 0;
    const vyclr = Math.abs(vy) <= SAFE_VY ? p.mid : Math.abs(vy) <= SAFE_VY * 1.6 ? p.warn : p.bad;
    this.engine.text('VY ' + Math.round(vy), W - 8, 38, 11, vyclr, 'right');

    // Horizontal speed
    const vx    = this.vx || 0;
    const vxclr = Math.abs(vx) <= SAFE_VX ? p.mid : Math.abs(vx) <= SAFE_VX * 2 ? p.warn : p.bad;
    this.engine.text('VX ' + Math.round(vx), W - 8, 52, 11, vxclr, 'right');

    // Angle
    const ang    = this.angle || 0;
    const absAng = Math.abs(((ang + 180) % 360 + 360) % 360 - 180);
    const aclr   = absAng <= SAFE_ANGLE ? p.mid : absAng <= SAFE_ANGLE * 2 ? p.warn : p.bad;
    this.engine.text('A ' + Math.round(ang) + '°', 52, 58, 11, aclr, 'left');

    // Angular velocity
    const om    = this.omega || 0;
    const omclr = Math.abs(om) <= SAFE_OMEGA ? p.mid : Math.abs(om) <= SAFE_OMEGA * 2 ? p.warn : p.bad;
    this.engine.text('ω ' + Math.round(om), W - 8, 66, 11, omclr, 'right');
  }

  // ---- Bottom button bar ----
  // Label convention (reaction-thruster):
  //   LEFT  button -> fires left nozzle -> nose tilts RIGHT (CW)
  //   RIGHT button -> fires right nozzle -> nose tilts LEFT (CCW)
  // Labels reflect the NOSE direction for clarity to the player.
  _drawButtons(ctx) {
    const p = P();

    const BW = 120;
    const bY = BTN_Y;
    const bH = BTN_H;

    const drawBtn = (bx, label, sublabel, active) => {
      ctx.fillStyle = active ? p.dim : p.dark;
      ctx.fillRect(bx, bY, BW, bH);

      ctx.strokeStyle = active ? p.hi : p.dim;
      ctx.lineWidth   = active ? 2.5 : 1.5;
      ctx.strokeRect(bx + 1, bY + 1, BW - 2, bH - 2);

      if (active) {
        ctx.fillStyle = p.hi;
        ctx.globalAlpha = Math.max(0, Math.min(1, 0.25));
        ctx.fillRect(bx + 2, bY + 2, BW - 4, 6);
        ctx.globalAlpha = 1;
      }

      const labelColor = active ? p.hi : p.fg;
      this.engine.text(label,    bx + BW / 2, bY + bH / 2 - 14, 13, labelColor, 'center');
      if (sublabel) {
        this.engine.text(sublabel, bx + BW / 2, bY + bH / 2 + 2,  10, active ? p.warn : p.dim, 'center');
      }
    };

    // LEFT button: nose tilts right (CW)    RIGHT button: nose tilts left (CCW)
    drawBtn(0,   '◄ TILT R',  'NOSE RIGHT', this._thrustRcsL);
    drawBtn(120, 'THRUST',    null,          this._thrustMain);
    drawBtn(240, 'TILT L ►', 'NOSE LEFT',  this._thrustRcsR);

    // Dividers
    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(120, bY); ctx.lineTo(120, H); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(240, bY); ctx.lineTo(240, H); ctx.stroke();
  }

  // ---- Stage Clear overlay ----
  _drawClearScreen(ctx) {
    const p  = P();
    const cx = W / 2;
    const cy = H / 2;

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.92));
    this.engine.rect(20, cy - 130, W - 40, 270, p.dark);
    this.engine.stroke(20, cy - 130, W - 40, 270, p.mid, 2);
    ctx.restore();

    this.engine.text('STAGE CLEAR!',                cx, cy - 116, 24, p.hi,   'center');
    this.engine.text('ST.' + this.stage + ' COMPLETE', cx, cy - 86, 13, p.mid, 'center');

    this.engine.text('STAGE SCORE',                 cx, cy - 62,  12, p.dim,  'center');
    this.engine.text('+' + (this._stageScore || 0), cx, cy - 46,  20, p.fg,   'center');
    this.engine.text('GUIDE BONUS +' + (this._guideBonus || 0), cx, cy - 22, 11, p.warn, 'center');

    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(40, cy + 4); ctx.lineTo(W - 40, cy + 4); ctx.stroke();

    this.engine.text('TOTAL SCORE',                 cx, cy + 14,  12, p.dim,  'center');
    this.engine.text('' + this.totalScore,          cx, cy + 30,  24, p.hi,   'center');
    this.engine.text('BEST ' + (this.high || 0),    cx, cy + 60,  14, p.mid,  'center');

    this.engine.text('TAP → STAGE ' + (this.stage + 1), cx, cy + 90, 14, p.fg,  'center');
    this.engine.text('BACK → MENU', cx, cy + 110, 11, p.dim, 'center');
  }

  // ---- Game Over overlay ----
  _drawGameOver(ctx) {
    const p  = P();
    const cx = W / 2;
    const cy = H / 2;

    ctx.save();
    ctx.globalAlpha = Math.max(0, Math.min(1, 0.92));
    this.engine.rect(20, cy - 120, W - 40, 250, p.dark);
    this.engine.stroke(20, cy - 120, W - 40, 250, p.bad, 2);
    ctx.restore();

    this.engine.text('GAME OVER',               cx, cy - 106, 28, p.bad,  'center');
    this.engine.text('CRASHED! ST.' + this.stage, cx, cy - 74, 13, p.warn, 'center');

    ctx.strokeStyle = p.dim;
    ctx.lineWidth   = 1;
    ctx.beginPath(); ctx.moveTo(40, cy - 54); ctx.lineTo(W - 40, cy - 54); ctx.stroke();

    this.engine.text('FINAL SCORE',             cx, cy - 40,  12, p.dim,  'center');
    this.engine.text('' + this.totalScore,       cx, cy - 24,  26, p.fg,   'center');

    ctx.beginPath(); ctx.moveTo(40, cy + 8); ctx.lineTo(W - 40, cy + 8); ctx.stroke();

    this.engine.text('BEST',                    cx, cy + 18,  11, p.dim,  'center');
    this.engine.text('' + (this.high || 0),     cx, cy + 34,  22, p.hi,   'center');

    this.engine.text('TAP TO RETRY',            cx, cy + 68,  14, p.fg,   'center');
    this.engine.text('BACK → MENU',        cx, cy + 88,  11, p.dim,  'center');
  }
}

;__games.push({ meta: meta, Game: Game });
})();

// ---- js/main.js (bootstrap) ----
// エントリポイント。エンジンを起動し、全ゲームを登録してメニューを表示する。

// 各ゲーム（meta + Game）。新しいゲームはここに import を1行足すだけで追加できる。

const GAMES = __games;
window.addEventListener('load', () => {
  const canvas = document.getElementById('screen');
  const engine = new Engine(canvas);

  // メニュー／ゲーム間の遷移ヘルパーをエンジンに生やす
  engine.toMenu = () => engine.changeScene(new MenuScene(engine, GAMES));
  engine.startGame = (g) => engine.changeScene(new g.Game(engine));

  engine.start(new MenuScene(engine, GAMES));
});

})();
